# from openai import OpenAIimport unicodedatafrom functools import lru_cacheimport jsonimport refrom docx import Documentfrom evaluation_gt import load_ground_truth_labels, evaluate_predictionsfrom docx.enum.text import WD_PARAGRAPH_ALIGNMENTimport pandas as pdfrom openpyxl.styles import Font, Alignment, PatternFillfrom openpyxl.utils import get_column_letterimport requestsfrom datetime import datetime, timedeltaimport pytzimport osimport numpy as npimport matplotlib.pyplot as pltfrom hvac_power_col_memory import batch_physical_role_review, get_slot_debug_info_from_cachefrom typing import List, Optional, Tupleimport traceback# ===== 列名规范化 =====def _canon_col_name(s: str) -> str:    s = str(s)    s = unicodedata.normalize('NFKC', s)    s = s.replace('\u3000', ' ')    s = s.replace('\ufeff', '')    s = re.sub(r'[\s\-]+', '', s)   # 去掉空格和连字符    return s.strip()# ===== 列名解析（用 GUI mapping 或 fallback）=====def resolve_col_name(col_name, df, canon2raw):    if not col_name:        return None    if col_name in df.columns:        return col_name    return canon2raw.get(_canon_col_name(col_name))# --- 单位选择缓存（减少同一列来回抖动） ---UNIT_CHOICE_CACHE = {}  # key: (flow_col, power_col) -> {"flow_unit":..., "power_unit":..., "score":..., "reason":...}STICKINESS_DELTA = 0.10  # 新组合必须比缓存分数至少高 0.10 才会覆盖# 初始化OpenAI客户端# client = OpenAI(api_key=os.environ['OPENAI_API_KEY'])os.makedirs("output", exist_ok=True)# ==== 本地 Qwen (Ollama) 客户端替代 OpenAI ====# 所有 client.chat.completions.create(...) 都会走这里OLLAMA_BASE_URL = "http://localhost:11434"OLLAMA_MODEL = "qwen2.5:7b"  # 你在命令行用的模型名def _ollama_chat(messages, temperature=0.0, json_mode=False, max_tokens=None):    """    使用 Ollama 的 /api/chat 接口。    messages: [{ "role": "system"/"user"/"assistant", "content": "..." }]    返回一次性完整的文本内容（非流式）。    """    payload = {        "model": OLLAMA_MODEL,        "messages": messages,        "stream": False,        "options": {"temperature": float(temperature)},    }    if json_mode:        # Ollama 支持 format="json"，会尽量输出合法 JSON        payload["format"] = "json"    import requests    resp = requests.post(f"{OLLAMA_BASE_URL}/api/chat", json=payload, timeout=600)    resp.raise_for_status()    data = resp.json()    # data["message"]["content"] 一般就是字符串    # print("[DEBUG] 调用Qwen消息条数:", len(messages))    return data["message"]["content"]class _DummyCompletions:    def create(self, model, messages, temperature=0.0, max_tokens=None,               response_format=None, **kwargs):        # 如果 response_format 要求 json_object，就打开 json_mode        json_mode = isinstance(response_format, dict) and \                    response_format.get("type") == "json_object"        text = _ollama_chat(            messages,            temperature=temperature,            json_mode=json_mode,            max_tokens=max_tokens,        )        # 伪造一个和 OpenAI SDK 类似的响应结构：response.choices[0].message.content        class _Msg: ...        class _Choice: ...        class _Resp: ...        m = _Msg()        m.content = text        c = _Choice()        c.message = m        r = _Resp()        r.choices = [c]        return rclass _DummyChat:    def __init__(self):        self.completions = _DummyCompletions()class DummyClient:    def __init__(self):        self.chat = _DummyChat()# 对外暴露的 client，接口和原来 OpenAI client 一样client = DummyClient()# ==== 常量定义区 ====TEMPERATURE_TAGS = [    'temperature', 'temperature_supply', 'temperature_return', 'temperature_other']POWER_TAGS = [    'power', 'power_instant', 'power_accum']FLOW_TAGS = [    'flow']# ========== 【全局stats安全读取工具】 ==========def safe_get_stats(result, prefer='cooling'):    """    从分析结果 result 中安全获取 cooling_stats 或 heating_stats 或 stats，没有则返回全None字典。    prefer: 'cooling' 优先冷，'heating' 优先热，'stats' 优先stats字段。    """    keys = ['mean', 'max', 'min', 'low_load_percentage', 'high_load_percentage']    stats = {}    if prefer == 'cooling':        stats = result.get('cooling_stats') or result.get('stats') or result.get('heating_stats') or {}    elif prefer == 'heating':        stats = result.get('heating_stats') or result.get('stats') or result.get('cooling_stats') or {}    else:        stats = result.get('stats') or result.get('cooling_stats') or result.get('heating_stats') or {}    if not isinstance(stats, dict):        stats = {}    # 保证所有字段都有    return {k: stats.get(k, None) for k in keys}# =============================================def normalize_column_names(df):    """标准化列名：Unicode规范化并去除空格"""    df.columns = [unicodedata.normalize('NFKC', str(col)).strip() for col in df.columns]    return dfdef identify_time_columns(df):    """识别时间列"""    time_cols = []    for col in df.columns:        if any(kw in col.lower() for kw in ['time', 'date', 'datetime', '時', '日']):            try:                pd.to_datetime(df[col], errors='raise')                time_cols.append(col)            except:                pass    return time_colsdef fetch_weather_data(location, start_date, end_date, api_key=None):    """    使用 openmeteo_requests 获取天气数据（新版 SDK 实现）    """    try:        import openmeteo_requests        import pandas as pd        import requests_cache        from retry_requests import retry        # 参数验证        if not isinstance(location, (tuple, list)) or len(location) != 2:            raise ValueError("location 参数应为 (纬度, 经度) 元组")        # 初始化缓存 + 重试机制        cache_session = requests_cache.CachedSession('.cache', expire_after=-1)        retry_session = retry(cache_session, retries=5, backoff_factor=0.2)        openmeteo = openmeteo_requests.Client(session=retry_session)        # 构建请求参数        url = "https://archive-api.open-meteo.com/v1/archive"        params = {            "latitude": location[0],            "longitude": location[1],            "start_date": start_date,            "end_date": end_date,            "hourly": ["temperature_2m", "relative_humidity_2m"]        }        responses = openmeteo.weather_api(url, params=params)        response = responses[0]  # 只处理第一个位置        hourly = response.Hourly()        time_index = pd.date_range(            start=pd.to_datetime(hourly.Time(), unit="s", utc=True),            end=pd.to_datetime(hourly.TimeEnd(), unit="s", utc=True),            freq=pd.Timedelta(seconds=hourly.Interval()),            inclusive="left"        )        df = pd.DataFrame({            "timestamp": time_index,            "temperature": hourly.Variables(0).ValuesAsNumpy(),            "humidity": hourly.Variables(1).ValuesAsNumpy()        })        return df    except Exception as e:        print(f"气象数据获取失败: {e}")        return None@lru_cache(maxsize=100)def ai_categorize_column(column_name, context="HVAC系统"):    """    AI辅助分类，支持temperature_supply, temperature_return, temperature_other    """    try:        response = client.chat.completions.create(            model="gpt-4o",            messages=[{                "role": "system",                "content": (                    "你是HVAC数据分析专家。请将以下列名分类为下列之一："                    "temperature_supply（供水温度、往水温度、supply、flow out、吹出温度、出风温度、送风温度、supply air等），"                    "temperature_return（回水温度、還水温度、return、flow in、吸込温度、入口温度、return air等），"                    "temperature_other（其他温度），"                    "air_volume（风量、air volume、风速、air flow、送风量、回风量、排风量等），"                    "humidity、pressure、flow（水流量、冷冻水流量等）、"                    "power_instant（瞬时功率、实时功率、fan power、室内机电力、风机电力、送风机功率等），"                    "power_accum（累计电力、積算電力、日累计、energy consumption），"                    "status、alarm、command、other。"                    "只返回上述分类名称中的一个，不要包含其他内容。"                )            }, {                "role": "user",                "content": f"列名: {column_name}"            }],            temperature=0.1        )        result = response.choices[0].message.content.lower().strip()        valid_categories = [            'temperature_supply', 'temperature_return', 'temperature_other',            'humidity', 'pressure', 'flow',            'power_instant', 'power_accum',            'status', 'alarm', 'command', 'other'        ]        return result if result in valid_categories else 'other'    except Exception as e:        print(f"AI分类失败: {e}")        return "other"def ai_batch_categorize_columns(column_names, client, batch_size=20):    """    批量AI归一列名。失败的批次自动降级为逐条询问，避免整批报“AI第X批分类失败”。    """    all_results = {}    for i in range(0, len(column_names), batch_size):        batch = column_names[i:i + batch_size]        prompt = (            "你是HVAC建筑系统专家。"            "下面是一批来自不同公司的HVAC数据列名，请逐个判定它们的物理意义，只返回标准英文角色名之一："            "['heat_source_supply_temp', 'heat_source_return_temp', 'heat_source_flow', 'heat_source_power', "            "'heat_source_capacity', 'terminal_supply_air_temp', 'terminal_return_air_temp', 'terminal_air_volume', "            "'terminal_power', 'terminal_capacity', 'other', 'status', 'alarm', 'command', 'humidity', 'pressure']"            "返回格式为严格JSON：{'列名1': '角色1', ...}。不要有其他输出。"            "注意：所有JSON中的字符串value禁止出现未转义的英文双引号，如需引号请用单引号。"            "\n列名：\n" + "\n".join(batch)        )        batch_result = ai_gpt_json_call(prompt, system_msg="你是HVAC物理量分类助手，只输出JSON。")        if isinstance(batch_result, dict) and batch_result:            all_results.update(batch_result)            continue        # === 批量失败 → 逐条降级 ===        had_any = False        for col in batch:            single_prompt = (                "你是HVAC建筑系统专家。请判定下面这个列名的物理意义，只返回上面白名单中的一个英文角色名。"                "返回严格JSON：{'列名': '角色'}。列名：\n" + col            )            one = ai_gpt_json_call(single_prompt, system_msg="你是HVAC物理量分类助手，只输出JSON。")            if isinstance(one, dict) and one:                # 兼容返回 {'AHP#-x y': 'heat_source_flow'} 或 {'列名': '角色'}                if col in one:                    all_results[col] = one[col]                else:                    # 只取第一个键值对                    k, v = next(iter(one.items()))                    all_results[k] = v                had_any = True        if not had_any:            print(f"[WARNING] AI分类失败：第{i // batch_size + 1}批（{len(batch)}列），已跳过。")    return all_resultsdef ai_group_columns_by_unit(column_list, lang='JP', client=None):    """    用GPT自动将所有列名进行【物理机组分组】。强制JSON，失败降级到容错解析。    """    assert column_list, "传入的column_list为空，请检查上游逻辑！"    if lang == 'JP':        prompt = (            "あなたは建築設備（HVAC）データ分析の専門家です。"            "以下のデータ列名リストは、多台数の空調・熱源・末端など機器の計測値です。"            "物理機器ごと（例：AHP#-3-1、AHP#-3-2 等）に明確に分けてください。"            "グループ名は必ず元の機器名や番号（例：AHP#-3-1）を使い、"            "各グループには供水温度、還水温度、流量、消費電力など、その機器の全ての関連列を含めてください。"            "必ずJSONのみで出力：{'AHP#-3-1': ['列1', '列2'], 'AHP#-3-2': ['列3', ...]}。"            "注意：JSONの値にダブルクォーテーション（\"）を使わず、必要な場合はシングルクォーテーション（'）にしてください。"        )    else:        prompt = (            "你是建筑设备（HVAC）数据分析专家。"            "以下是多台空调、热源、末端设备的数据列名。"            "请严格以物理机组或设备（如AHP#-3-1、AHP#-3-2等）分组，组名必须用原始机组编号，"            "每组包含该设备全部相关字段（如供水温度、回水温度、流量、功率、容量等）。"            "只返回严格JSON：{'AHP#-3-1': ['列1', '列2'], 'AHP#-3-2': ['列3', ...]}，不要写解释。"            "注意：所有JSON中的字符串禁止未转义的英文双引号，如需引号请用单引号。"        )    joined = "\n".join(column_list)    full_prompt = prompt + "\n" + joined    try:        # 优先强制 JSON        resp = client.chat.completions.create(            model="gpt-4o",            messages=[                {"role": "system", "content": "你是HVAC数据分组专家，返回必须严格是JSON！"},                {"role": "user", "content": full_prompt}            ],            temperature=0.0,            max_tokens=2000,            response_format={"type": "json_object"},        )        content = resp.choices[0].message.content.strip()        return json.loads(content)    except Exception:        # 降级容错        try:            resp = client.chat.completions.create(                model="gpt-4o",                messages=[                    {"role": "system", "content": "你是HVAC数据分组专家，返回必须严格是JSON！"},                    {"role": "user", "content": full_prompt}                ],                temperature=0.0,                max_tokens=2000,            )            content = resp.choices[0].message.content.strip()            return robust_json_parse(content)        except Exception as e:            print(f"[AI分组失败] {e}")            return {}def find_related_columns(column_info, group_mode='ai', client=None, lang='JP'):    """    column_info: {列名: 角色}    group_mode: 'ai' 用 GPT 分组；其它值用正则分组    """    # ========== 1) 正则分组（保持兼容） ==========    if group_mode != 'ai':        related = {}        prefix_pattern = r'(AHP#-[\d-]+)'        prefix_groups = {}        for col in column_info:            import re            if match := re.match(prefix_pattern, col):                prefix = match.group(1)                prefix_groups.setdefault(prefix, []).append(col)        for idx, (prefix, cols) in enumerate(prefix_groups.items(), 1):            if len(cols) >= 2:                related[f'Unit_{idx}'] = {                    'columns': cols,                    'type': 'by_unit',                    'description': f'設備{idx}に関するデータ'                }        return related    # ========== 2) AI 分组逻辑 ==========    from inspect import currentframe    g = currentframe().f_back.f_globals    if client is None:        client = g.get('client')    # 1) 调用 GPT 分组函数    column_list = list(column_info.keys())    groups = ai_group_columns_by_unit(column_list, lang=lang, client=client)    # 2) 把 GPT 输出的“短列名”解析回真实列名    df_cols = set(column_info.keys())    related = {}    for group, cols in groups.items():        resolved_cols = []        for c in cols:            c_str = str(c).strip()            # a) 完全匹配            if c_str in df_cols:                resolved_cols.append(c_str)                continue            # b) {group}+空格+短名            cand1 = f"{group} {c_str}"            if cand1 in df_cols:                resolved_cols.append(cand1)                continue            # c) 模糊匹配 group+短名            cands = [dc for dc in df_cols if (group in dc and c_str in dc)]            if cands:                resolved_cols.append(min(cands, key=len))                continue            # d) 仅短名模糊匹配            cands2 = [dc for dc in df_cols if c_str in dc]            if cands2:                resolved_cols.append(min(cands2, key=len))                continue            resolved_cols.append(c_str)        related[group] = {            "columns": resolved_cols,            "type": "ai_group",            "description": f"AI自動分组：{group}"        }    return relateddef generate_visualizations(df, related_columns, chart_type=0, output_dir="output"):    """生成可视化图表"""    os.makedirs(output_dir, exist_ok=True)    chart_paths = []    for group_name, group_info in related_columns.items():        cols = group_info['columns']        if len(cols) < 1:            continue        plt.figure(figsize=(10, 6))        if chart_type == 0:  # 折线图            df[cols].plot(title=group_info['description'])        elif chart_type == 1:  # 柱状图            df[cols].mean().plot(kind='bar', title=f"{group_info['description']}均值对比")        chart_path = os.path.join(output_dir, f"{group_name}.png")        plt.savefig(chart_path)        plt.close()        chart_paths.append(chart_path)    return chart_pathsdef export_to_excel(        explanations, column_info, operation_analysis=None, lang='JP', output_path="hvac_report.xlsx"):    print("[DEBUG] 当前工作目录:", os.getcwd())    print("[DEBUG] export_to_excel调用, 输出路径:", output_path)    # print("【EXPORT_TO_EXCEL】explanations:", explanations)    # print("【EXPORT_TO_EXCEL】column_info:", column_info)    print("【EXPORT_TO_EXCEL】operation_analysis:", operation_analysis)    print("【EXPORT_TO_EXCEL】output_path:", output_path)    # === 加入调试检查 ===    for k, v in explanations.items():        if v is None or (isinstance(v, float) and pd.isna(v)):            print(f"[WARNING] explanations[{k}] 为 None 或 NaN")        if not isinstance(v, str):            print(f"[WARNING] explanations[{k}] 不是 str, 实际类型: {type(v)}")    # ==================    """生成Excel报告"""    try:        # 创建输出目录        out_dir = os.path.dirname(output_path)        if out_dir and out_dir.strip() != "":            os.makedirs(out_dir, exist_ok=True)        # 列分类表        rows = []        for col, exp in explanations.items():            rows.append({                "列名" if lang == 'JP' else "Column": str(col),                "分類" if lang == 'JP' else "Category": column_info.get(col, '不明' if lang == 'JP' else 'Unknown'),                "説明" if lang == 'JP' else "Description": exp if exp else "-"            })        df_classify = pd.DataFrame(rows)        # 写入Excel        with pd.ExcelWriter(output_path, engine='openpyxl') as writer:            # Sheet1: 列名分类            df_classify.to_excel(writer, sheet_name="列名分類" if lang == 'JP' else "Classification", index=False)            # Sheet2: 运行分析（如果有）            if operation_analysis:                ana_rows = []                for unit, analysis in operation_analysis.items():                    for line in analysis.split('\n'):                        if line.strip():                            ana_rows.append({"机组/Unit": unit, "分析/Analysis": line.strip()})                if ana_rows:                    pd.DataFrame(ana_rows).to_excel(writer,                                                    sheet_name="運転状態分析" if lang == 'JP' else "OperationAnalysis",                                                    index=False)            # Sheet3: 元数据（可选，添加生成日期等）            meta = pd.DataFrame({                "生成日時" if lang == 'JP' else "Generated At": [datetime.now().strftime('%Y-%m-%d %H:%M:%S')]            })            meta.to_excel(writer, sheet_name="メタ情報" if lang == 'JP' else "Meta", index=False)        print("[DEBUG] Excel报告已保存到:", output_path)        return output_path    except Exception as e:        print(f"excel报告生成失败: {e}")        import traceback        traceback.print_exc()        raise  # 关键是这一行    finally:        print("[EXPORT TO WORD FINISHED]")def rearrange_excel_with_groups(df, related_columns, original_path):    """Excel分组输出"""    if not related_columns:        output_path = original_path.replace('.xlsx', '_nogroup.xlsx')        df.to_excel(output_path, index=False)        return output_path    new_df = pd.DataFrame()    group_colors = ['DDDDDD', 'EEEEEE', 'F5F5F5']    for i, (group_name, group_info) in enumerate(related_columns.items()):        new_df[f"【{group_name}】"] = group_info.get('description', '')        valid_cols = [col for col in group_info['columns'] if col in df.columns]        new_df = pd.concat([new_df, df[valid_cols]], axis=1)        if i < len(related_columns) - 1:            new_df[f"_间隔_{i}"] = ""    output_path = original_path.replace('.xlsx', '_grouped.xlsx')    with pd.ExcelWriter(output_path, engine='openpyxl') as writer:        new_df.to_excel(writer, index=False)        ws = writer.sheets['Sheet1']        for col_num, col_name in enumerate(new_df.columns, 1):            if "【" in str(col_name):                ws.cell(1, col_num).font = Font(bold=True)                ws.cell(1, col_num).fill = PatternFill("solid", fgColor=group_colors[col_num % 3])            elif "_间隔_" in str(col_name):                ws.column_dimensions[get_column_letter(col_num)].width = 3    return output_pathdef analyze_and_plot_load_vs_weather(    load_ratio_series, weather_df, time_index_col='timestamp', lang='JP', output_prefix='output'):    """    1. 合并负荷率和外气温度    2. 输出相关系数    3. 分外气温区间统计负荷率分布    4. 可视化    """    # 合并数据    merged = pd.DataFrame({'load_ratio': load_ratio_series})    weather_df = weather_df.set_index(time_index_col)    # ===== tz兼容性修正（关键）=====    # merged.index, weather_df.index 都转为 tz-naive    if hasattr(merged.index, "tz") and merged.index.tz is not None:        merged.index = merged.index.tz_localize(None)    if hasattr(weather_df.index, "tz") and weather_df.index.tz is not None:        weather_df.index = weather_df.index.tz_localize(None)    # =================================    merged = merged.join(weather_df, how='left')    merged.dropna(subset=['load_ratio', 'temperature'], inplace=True)    # 相关系数    corr = merged[['load_ratio', 'temperature']].corr().iloc[0, 1]    print(f"{'負荷率-外気温度相関係数' if lang == 'JP' else '负荷率-外气温度相关系数'}: {corr:.3f}")    # 画散点图    scatter_path = f'{output_prefix}/load_vs_temp_scatter.png'    plt.figure(figsize=(7,5))    plt.scatter(merged['temperature'], merged['load_ratio'], alpha=0.5)    plt.xlabel('外気温度(℃)' if lang == 'JP' else '外气温度(℃)')    plt.ylabel('負荷率(%)' if lang == 'JP' else '负荷率(%)')    plt.title('外気温度-負荷率散布図' if lang == 'JP' else '外气温度-负荷率散点图')    plt.grid(True)    plt.tight_layout()    plt.savefig(scatter_path)    plt.close()    # 分外气温区间统计负荷率分布    bins = np.arange(0, 41, 2)  # 0-40度，每2度一档    merged['temp_bin'] = pd.cut(merged['temperature'], bins)    group_stats = merged.groupby('temp_bin', observed=True)['load_ratio'].agg(['count', 'mean', 'median', 'std'])    # group_stats = merged.groupby('temp_bin')['load_ratio'].agg(['count', 'mean', 'median', 'std'])    print(group_stats)    # 画箱线图    boxplot_path = f'{output_prefix}/load_vs_temp_boxplot.png'    plt.figure(figsize=(12,6))    merged.boxplot(column='load_ratio', by='temp_bin', grid=False, rot=45)    plt.xlabel('外気温度区間(℃)' if lang == 'JP' else '外气温区间(℃)')    plt.ylabel('負荷率(%)' if lang == 'JP' else '负荷率(%)')    plt.title('外気温度ごとの負荷率分布' if lang == 'JP' else '不同外气温区间下的负荷率分布')    plt.suptitle('')    plt.tight_layout()    plt.savefig(boxplot_path)    plt.close()    return corr, group_stats, merged, scatter_path, boxplot_pathdef safe_fmt(val, fmt=".1f", default="N/A", unit=""):    try:        # 处理 None、空字符串、NaN        if val is None or (isinstance(val, float) and pd.isna(val)):            return default        return f"{float(val):{fmt}}{unit}"    except Exception:        # 如果是字符串或其他类型（比如 "N/A"），原样返回        return f"{val}{unit}" if val not in [None, "", np.nan] else defaultdef analyze_load_ratio_multiunit(    df, related_columns,    cooling_capacity_dict=None,    lang='JP',    weather_df=None,    weather_time_col='timestamp',    unit_db=None,    client=None,    role_dict=None,    ai_roles=None,    slot_details=None,    canon2raw=None,):    client = client or globals().get('client')    results = {}    def _ratio_pct(series: pd.Series, cond) -> float:        s = pd.to_numeric(series, errors="coerce").dropna()        if s.empty:            return np.nan        return float(cond(s).mean() * 100.0)    # 如果外面没传，就自己算；如果传了，就直接用传进来的结果    if role_dict is None or ai_roles is None or slot_details is None:        role_dict, ai_roles, slot_details = batch_physical_role_review(            df,            client,            unit_infer=slot_unit_infer,        )    # 如果某个列在 role_dict 里没标角色，就从 ai_roles 里兜底    for c, r in ai_roles.items():        if c not in role_dict and r in [            "heat_source_supply_temp", "heat_source_return_temp",            "heat_source_flow", "heat_source_power", "heat_source_capacity",            "terminal_supply_air_temp", "terminal_return_air_temp",            "terminal_air_volume", "terminal_power", "terminal_capacity"        ]:            role_dict[c] = r    stats = {}    for group_name, group_info in related_columns.items():        # —— 工具：按“角色”从本组找列 ——        def _pick_by_role(group_cols, roles_map, role):            for c in group_cols:                if roles_map.get(c) == role:                    return c            return None        # —— 打印组内角色映射（便于排查）——        cols = group_info['columns']        group_roles = {col: role_dict.get(col, "") for col in cols}        # print(f"  全部字段物理量： {group_roles}")        # —— 先按角色挑热源4要素 ——        heat_source_supply_temp_col = _pick_by_role(cols, group_roles, "heat_source_supply_temp")        heat_source_return_temp_col = _pick_by_role(cols, group_roles, "heat_source_return_temp")        heat_source_flow_col = _pick_by_role(cols, group_roles, "heat_source_flow")        heat_source_power_col = _pick_by_role(cols, group_roles, "heat_source_power")        heat_source_capacity_col = _pick_by_role(cols, group_roles, "heat_source_capacity")        heat_source_supply_temp_col = resolve_col_name(heat_source_supply_temp_col,df, canon2raw)        heat_source_return_temp_col = resolve_col_name(heat_source_return_temp_col,df, canon2raw)        heat_source_flow_col = resolve_col_name(heat_source_flow_col,df, canon2raw)        heat_source_power_col = resolve_col_name(heat_source_power_col,df, canon2raw)        heat_source_capacity_col = resolve_col_name(heat_source_capacity_col,df, canon2raw)        # —— 若缺功率：尝试用累计能耗列（power_accum 或名称里有 kWh/Wh/積算/電力量 等）派生 ——        if heat_source_power_col is None:            # 先看 AI/兜底标了 power_accum 的列            power_accum_col = _pick_by_role(cols, group_roles, "power_accum")            # 再用列名兜底挑一个“能量像”的列            if power_accum_col is None:                ENERGY_HINT = re.compile(r"(?:energy|積算|電力量|kwh|wh|mwh|累计|累積)", re.IGNORECASE)                for c in cols:                    name = str(c)                    if ENERGY_HINT.search(name) and not any(tok in name for tok in                                                            ["温度", "還温", "往温", "圧力", "pressure", "temp",                                                             "status", "alarm", "command", "INV", "%", "開度", "SP",                                                             "設定", "code"]):                        power_accum_col = c                        break            # 能量列 → 派生功率列（kW）            if power_accum_col is not None:                derived = derive_power_from_energy(                    df,                    time_col=df.index.name if isinstance(df.index, pd.DatetimeIndex) else (                        list(df.columns)[0] if len(df.columns) > 0 else None),                    energy_col=power_accum_col,                    new_col_name=f"{power_accum_col} 電力(kW)"                )                if derived and derived in df.columns:                    heat_source_power_col = derived                    # 新生成列加入本组参与后续计算                    if derived not in cols:                        cols.append(derived)                        group_roles[derived] = "heat_source_power"        # —— 如果四要素齐活，先做数值强转，避免 “unsupported operand type(s) for -: 'str' and 'str'” ——        needed_cols_now = [heat_source_supply_temp_col, heat_source_return_temp_col, heat_source_flow_col,                           heat_source_power_col]        for _c in [c for c in needed_cols_now if c is not None]:            df[_c] = pd.to_numeric(df[_c], errors='coerce')        # 末端字段        terminal_supply_air_temp_col = next((c for c, r in group_roles.items() if r == "terminal_supply_air_temp"),                                            None)        terminal_return_air_temp_col = next((c for c, r in group_roles.items() if r == "terminal_return_air_temp"),                                            None)        terminal_air_volume_col = next((c for c, r in group_roles.items() if r == "terminal_air_volume"), None)        terminal_power_col = next((c for c, r in group_roles.items() if r == "terminal_power"), None)        terminal_capacity_col = next((c for c, r in group_roles.items() if r == "terminal_capacity"), None)        terminal_supply_air_temp_col = resolve_col_name(terminal_supply_air_temp_col,df, canon2raw)        terminal_return_air_temp_col = resolve_col_name(terminal_return_air_temp_col,df, canon2raw)        terminal_air_volume_col = resolve_col_name(terminal_air_volume_col,df, canon2raw)        terminal_power_col = resolve_col_name(terminal_power_col,df, canon2raw)        terminal_capacity_col = resolve_col_name(terminal_capacity_col,df, canon2raw)        # 1. 用AI抽取该组最优列（都是新角色名key）        col_sel = gpt_pick_cop_columns_for_group(group_info['columns'], group_name, lang)        if not col_sel:            continue        # 2. 获取额定冷量（优先外部传入，否则用AI选的能力字段）        unit_capacity = None        if cooling_capacity_dict and isinstance(cooling_capacity_dict, dict):            unit_capacity = cooling_capacity_dict.get(group_name)        if not unit_capacity and heat_source_capacity_col and heat_source_capacity_col in df.columns:            unit_capacity = pd.to_numeric(df[heat_source_capacity_col], errors='coerce').max()        if (unit_capacity is None) or pd.isna(unit_capacity) or (unit_capacity <= 0):            continue        # 3. 热源负荷率分析：用AI选出来的热源物理量        stats_cooling = None        cooling_load_ratio = pd.Series(dtype=float)        stats_heating = None        heating_load_ratio = pd.Series(dtype=float)        if all([heat_source_supply_temp_col, heat_source_return_temp_col, heat_source_flow_col, heat_source_power_col]):            if not all(x in df.columns for x in                       [heat_source_supply_temp_col, heat_source_return_temp_col, heat_source_flow_col,                        heat_source_power_col]):                continue            supply = df[heat_source_supply_temp_col]            return_ = df[heat_source_return_temp_col]            flow_rate = df[heat_source_flow_col]            power = df[heat_source_power_col]            # 先用和 COP 相同的“单位复判”拿到最佳单位            combo = guess_best_unit_combo_with_retry(                df,                heat_source_supply_temp_col,                heat_source_return_temp_col,                heat_source_flow_col,                heat_source_power_col,                unit_db or {}, client            )            # 统一把流量换到 L/s，再用 Q[kW] = 4.18 * (L/s) * ΔT            fu = (combo or {}).get("flow_unit") or unit_db.get(heat_source_flow_col, {}).get("unit") or "m³/h"            delta = return_ - supply            is_cooling = delta > 0            # 统一把流量换到 L/s            fu = (combo or {}).get("flow_unit") or (unit_db or {}).get(heat_source_flow_col, {}).get("unit") or "m³/h"            flow_lps = convert_flow(flow_rate, fu)  # -> L/s            # 用带索引的 Series 构造冷/热量（kW）            cooling_power = pd.Series(np.nan, index=df.index)            heating_power = pd.Series(np.nan, index=df.index)            cooling_power.loc[is_cooling] = flow_lps.loc[is_cooling] * 4.18 * delta.loc[is_cooling]            heating_power.loc[~is_cooling] = flow_lps.loc[~is_cooling] * 4.18 * (-delta.loc[~is_cooling])            # 负荷率（%）            valid_cooling = (power > 0) & cooling_power.notna()            valid_heating = (power > 0) & heating_power.notna()            cooling_load_ratio = ((cooling_power / unit_capacity) * 100).where(valid_cooling)            heating_load_ratio = ((heating_power / unit_capacity) * 100).where(valid_heating)            # 清理无穷            cooling_load_ratio = cooling_load_ratio.replace([np.inf, -np.inf], np.nan)            heating_load_ratio = heating_load_ratio.replace([np.inf, -np.inf], np.nan)            # 分别统计冷/热工况负荷率            stats_cooling = {                'mean': cooling_load_ratio.mean(),                'max': cooling_load_ratio.max(),                'min': cooling_load_ratio.min(),                'low_load_percentage': _ratio_pct(cooling_load_ratio, lambda s: s < 30),                'high_load_percentage': _ratio_pct(cooling_load_ratio, lambda s: s > 80),            }            stats_heating = {                'mean': heating_load_ratio.mean(),                'max': heating_load_ratio.max(),                'min': heating_load_ratio.min(),                'low_load_percentage': _ratio_pct(heating_load_ratio, lambda s: s < 30),                'high_load_percentage': _ratio_pct(heating_load_ratio, lambda s: s > 80),            }        # 末端负荷率分析（与热源负荷率结构一致）        if all([terminal_supply_air_temp_col, terminal_return_air_temp_col, terminal_air_volume_col,                terminal_capacity_col]):            # 检查全部列在DataFrame中            if not all(x in df.columns for x in [                terminal_supply_air_temp_col,                terminal_return_air_temp_col,                terminal_air_volume_col,                terminal_capacity_col            ]):                continue  # 缺列跳过            # 1. 计算末端冷量            # 通常风量单位 m3/h，温度 ℃            supply_temp = df[terminal_supply_air_temp_col]            return_temp = df[terminal_return_air_temp_col]            air_volume = df[terminal_air_volume_col]  # m3/h            terminal_capacity = df[terminal_capacity_col]  # kW，假定是“单点能力”，否则用 max() 或配置给定            cooling_power_terminal = 1.2 * air_volume * (return_temp - supply_temp) / 3600  # kW            # 有时末端能力是常数，不是列，需处理            if isinstance(terminal_capacity, pd.Series):                unit_capacity_terminal = terminal_capacity.max()            else:                unit_capacity_terminal = terminal_capacity  # 如果是单值            # 2. 负荷率计算            # 排除异常和能力为0的情况            valid_idx_terminal = (unit_capacity_terminal > 0) & (~cooling_power_terminal.isna())            load_ratio_terminal = pd.Series(np.where(                unit_capacity_terminal[valid_idx_terminal] != 0,                cooling_power_terminal[valid_idx_terminal] / unit_capacity_terminal[valid_idx_terminal] * 100,                np.nan            ))            load_ratio_terminal = load_ratio_terminal.replace([np.inf, -np.inf], np.nan)            # 3. 统计            stats_terminal = {                'mean': load_ratio_terminal.mean(),                'max': load_ratio_terminal.max(),                'min': load_ratio_terminal.min(),                'low_load_percentage': _ratio_pct(load_ratio_terminal, lambda s: s < 30),                'high_load_percentage': _ratio_pct(load_ratio_terminal, lambda s: s > 80),            }            # 4. 输出到results字典            results[group_name + "_terminal"] = {                'stats': stats_terminal,                'load_ratio_data': load_ratio_terminal,                'columns_used': {                    'supply_air_temp': terminal_supply_air_temp_col,                    'return_air_temp': terminal_return_air_temp_col,                    'air_volume': terminal_air_volume_col,                    'capacity': terminal_capacity_col                },                'unit_capacity': unit_capacity_terminal            }        # ====== 新增：天气相关分析 ======        weather_corr = None        weather_group_stats = None        weather_scatter = None        weather_boxplot = None        weather_merged = None        if (weather_df is not None) and isinstance(cooling_load_ratio,                                                   pd.Series) and cooling_load_ratio.dropna().size > 1:            output_prefix = f'output/{group_name}'            os.makedirs(output_prefix, exist_ok=True)            weather_corr, weather_group_stats, weather_merged, weather_scatter, weather_boxplot = analyze_and_plot_load_vs_weather(                cooling_load_ratio.dropna(), weather_df, time_index_col=weather_time_col, lang=lang,                output_prefix=output_prefix            )        # ===============================        # 5. 生成AI专业报告（每台单独一段）——用冷负荷率作为主报告        base_stats = stats_cooling if isinstance(stats_cooling, dict) else {}        has_valid_stats = any(pd.notna(base_stats.get(k)) for k in ['mean', 'max', 'min'])        if not has_valid_stats:            analysis_text = "分析不可用：负荷率有效样本不足。"        else:            try:                weather_comment = ""                if weather_corr is not None:                    if lang == 'JP':                        weather_comment = f"\n【気象連動】負荷率と外気温度の相関係数は {weather_corr:.3f} です。"                    else:                        weather_comment = f"\n【天气相关】负荷率与外气温度的相关系数为 {weather_corr:.3f}。"                base_stats = stats_cooling if isinstance(stats_cooling, dict) else {}                if lang == 'JP':                    prompt = (                        f"{group_name} の空調システム負荷率（冷房）分析結果:\n"                        f"平均負荷率: {safe_fmt(base_stats.get('mean'))}%\n"                        f"最大負荷率: {safe_fmt(base_stats.get('max'))}%\n"                        f"最低負荷率: {safe_fmt(base_stats.get('min'))}%\n"                        f"低負荷率(30%未満)時間割合: {safe_fmt(base_stats.get('low_load_percentage'))}%\n"                        f"高負荷率(80%超)時間割合: {safe_fmt(base_stats.get('high_load_percentage'))}%\n"                        f"{weather_comment}\n"                        "以下の点について専門的な観点から解説してください:\n"                        "1. システムの負荷特性\n"                        "2. 低負荷率が続く場合の影響\n"                        "3. 高負荷率が続く場合の影響\n"                        "4. エネルギー効率改善の可能性\n"                        "5. システム設計との適合性\n\n"                        "専門的ですが分かりやすい日本語で、箇条書きで報告してください。"                    )                else:                    prompt = (                        f"{group_name} 空调系统负荷率（制冷）分析结果:\n"                        f"平均负荷率: {safe_fmt(base_stats.get('mean'))}%\n"                        f"最大负荷率: {safe_fmt(base_stats.get('max'))}%\n"                        f"最低负荷率: {safe_fmt(base_stats.get('min'))}%\n"                        f"低负荷率(30%以下)时间占比: {safe_fmt(base_stats.get('low_load_percentage'))}%\n"                        f"高负荷率(80%以上)时间占比: {safe_fmt(base_stats.get('high_load_percentage'))}%\n"                        f"{weather_comment}\n"                        "请从专业角度分析以下方面:\n"                        "1. 系统负荷特性\n"                        "2. 长期低负荷运行的影响\n"                        "3. 长期高负荷运行的影响\n"                        "4. 能效改进可能性\n"                        "5. 与系统设计的匹配性\n\n"                        "请使用专业但易懂的中文，以项目符号列表形式报告。"                    )                response = client.chat.completions.create(                    model="gpt-4o",                    messages=[                        {"role": "system", "content": "你是一个HVAC系统专家，能够分析系统运行负荷特性"},                        {"role": "user", "content": prompt}                    ]                )                analysis_text = response.choices[0].message.content            except Exception as e:                print(f"负荷率分析报告生成失败（{group_name}）: {e}")                analysis_text = "分析不可用"            results[group_name] = {                'cooling_stats': stats_cooling,                'cooling_load_ratio': cooling_load_ratio,                'heating_stats': stats_heating,                'heating_load_ratio': heating_load_ratio,                'columns_used': col_sel,                'unit_capacity': unit_capacity,                'analysis': analysis_text,                # 天气相关输出                'weather_corr': weather_corr,                'weather_group_stats': weather_group_stats,                'weather_scatter': weather_scatter,                'weather_boxplot': weather_boxplot,                'weather_merged': weather_merged,            }    return resultsdef robust_json_parse(content: str):    """    坚固型 JSON 解析：    1) 先尝试标准 json.loads    2) 失败则做清洗（去掉代码块、替换智能引号、去掉尾逗号）    3) 再失败则用正则“容错提取” unit / reason / convert_tip    """    import json, re    if content is None:        return {}    text = str(content).strip()    # 去掉代码块围栏 ```json ... ```    if text.startswith("```"):        text = re.sub(r"^```(?:json)?\s*|\s*```$", "", text, flags=re.IGNORECASE | re.DOTALL).strip()    # 常见清洗：智能引号 -> 普通，引号里的换行 -> 空格    trans = {        "“": '"', "”": '"', "「": '"', "」": '"', "『": '"', "』": '"',        "’": "'", "‘": "'"    }    for k, v in trans.items():        text = text.replace(k, v)    text = re.sub(r'\r?\n', ' ', text)    # 尝试直接解析    try:        return json.loads(text)    except Exception:        pass    # 去掉 JSON 尾逗号（简易版）    text_no_trailing_comma = re.sub(r',\s*([}\]])', r'\1', text)    try:        return json.loads(text_no_trailing_comma)    except Exception:        pass    # 最后容错提取（即使内部有未转义的引号也尽量提出来）    result = {}    # 提取 "unit"    m = re.search(r'(?:["\']unit["\']\s*[:：]\s*)(["\']?)([A-Za-zμm³°/%\-\w]+)\1', text, re.IGNORECASE)    if m:        result["unit"] = m.group(2)    # 提取 "reason"    m = re.search(r'(?:["\']reason["\']\s*[:：]\s*)(["\'])(.+?)\1', text, re.IGNORECASE)    if m:        result["reason"] = m.group(2)    else:        # 容忍无引号：截到下一个键名或行尾        m2 = re.search(r'(?:["\']reason["\']\s*[:：]\s*)(.+?)(?:,\s*["\']\w+["\']\s*:|$)', text, re.IGNORECASE)        if m2:            result["reason"] = m2.group(1).strip()    # 提取 "convert_tip"    m = re.search(r'(?:["\']convert_tip["\']\s*[:：]\s*)(["\'])(.+?)\1', text, re.IGNORECASE)    if m:        result["convert_tip"] = m.group(2)    return resultdef ai_gpt_json_call(    prompt,    system_msg="你是专业分类助手，只输出JSON，不要注释，注意所有JSON中的字符串字段禁止出现未转义的英文双引号，如需引号请用单引号。",    model="gpt-4o",    max_tokens=2048,    temperature=0.0):    try:        # 尝试1：强制 JSON 输出        try:            response = client.chat.completions.create(                model=model,                messages=[                    {"role": "system", "content": system_msg},                    {"role": "user", "content": prompt}                ],                temperature=temperature,                max_tokens=max_tokens,                response_format={"type": "json_object"},            )            ai_output = response.choices[0].message.content            return json.loads(ai_output)        except Exception as e_force:            # 尝试2：普通文本 + 容错解析            response = client.chat.completions.create(                model=model,                messages=[                    {"role": "system", "content": system_msg},                    {"role": "user", "content": prompt}                ],                temperature=temperature,                max_tokens=max_tokens,            )            ai_output = response.choices[0].message.content            parsed = robust_json_parse(ai_output)            return parsed if isinstance(parsed, dict) else {}    except Exception as e:        print(f"[GPT接口异常] {e}")        try:            with open("gpt_error_log.txt", "a", encoding="utf-8") as f:                f.write(f"\n=== [接口异常] {repr(e)} ===\n")        except Exception:            pass        return {}def gpt_pick_cop_columns_for_group(col_list, group_name, lang='JP'):    """    让GPT在给定机组（组内）所有列中，挑选出COP所需字段（强制 JSON，失败降级）。    """    prompt = (        f"你是建筑暖通专家，以下是某台机组({group_name})的所有列名：\n"        + "\n".join(col_list) + "\n"        "请在这些列名中严格挑选出【供水温度】【回水温度】【流量】【消費電力】【冷却/加热能力】5个字段，"        "消費電力/運転容量等只作为消耗功率power，冷却能力/加热能力等只作为能力capacity，绝不能混用。\n"        "每个字段只输出1个你最推荐的列名（如果没有请填null）。"        "用如下JSON格式返回：\n"        "{"        "  'heat_source_supply_temp': '列名',"        "  'heat_source_return_temp': '列名',"        "  'heat_source_flow': '列名',"        "  'heat_source_power': '列名',"        "  'heat_source_capacity': '列名',"        "  'terminal_supply_air_temp': '列名',"        "  'terminal_return_air_temp': '列名',"        "  'terminal_air_volume': '列名',"        "  'terminal_power': '列名',"        "  'terminal_capacity': '列名'"        "}"        "注意：所有value如需引号请用单引号，不允许未转义的英文双引号。"    )    try:        # 强制 JSON        resp = client.chat.completions.create(            model="gpt-4o",            messages=[                {"role": "system", "content": "你是HVAC数据分析专家，能理解每个列名的物理意义和单位。"},                {"role": "user", "content": prompt}            ],            temperature=0.0,            max_tokens=256,            response_format={"type": "json_object"},        )        return json.loads(resp.choices[0].message.content)    except Exception:        # 降级容错        try:            resp = client.chat.completions.create(                model="gpt-4o",                messages=[                    {"role": "system", "content": "你是HVAC数据分析专家，能理解每个列名的物理意义和单位。"},                    {"role": "user", "content": prompt}                ],                temperature=0.0,                max_tokens=256,            )            return robust_json_parse(resp.choices[0].message.content)        except Exception as e:            print(f"[GPT列名自动抽取失败] {e}")            return Nonedef calc_terminal_cop(df, inlet_temp_col, outlet_temp_col, air_volume_col, terminal_power_col):    """末端COP计算：风量 × ΔT / 电力"""    # 1.2 是常用的比热乘密度（kg/m³ × kJ/kg℃），单位换算请确保一致    df = df.dropna(subset=[inlet_temp_col, outlet_temp_col, air_volume_col, terminal_power_col])    df['冷量_kW'] = 1.2 * df[air_volume_col] * (df[inlet_temp_col] - df[outlet_temp_col]) / 3600    df['COP'] = np.where(df[terminal_power_col] > 0.5, df['冷量_kW'] / df[terminal_power_col], np.nan)    df['COP'] = df['COP'].replace([np.inf, -np.inf], np.nan)    df['COP_valid'] = filter_valid_cop(df['COP'])    return df[['COP_valid', 'COP', '冷量_kW', terminal_power_col]]def first_n_valid(series, n=10):    # 返回非零且非空前n个，类型安全    return series[(series != 0) & (~series.isna())].head(n).tolist()from datetime import datetimeimport osdef save_column_name_validation(    role_dict: dict,    out_dir: str = r"D:\dynamoFile\PythonScript\LLM\output\column_name_validation",    extra_info: dict | None = None,):    """    将本次列名识别结果保存为一个 txt 供人工参考。    role_dict: {column_name: role}  —— 最终识别的物理角色（C1–C8加权之后的结果）    extra_info: 预留字段，比如以后想把 slot 分数、AI 原始猜测也写进去    """    try:        os.makedirs(out_dir, exist_ok=True)        ts = datetime.now().strftime("%Y%m%d_%H%M%S")        file_path = os.path.join(out_dir, f"column_validation_{ts}.txt")        with open(file_path, "w", encoding="utf-8") as f:            f.write("# column_name\trole\n")            for col, role in role_dict.items():                f.write(f"{col}\t{role}\n")            # 以后想扩展就用 extra_info            if extra_info:                f.write("\n# extra_info (debug)\n")                for k, v in extra_info.items():                    f.write(f"# {k}: {v}\n")        print(f"[INFO] 列名验证结果已保存: {file_path}")    except Exception as e:        print(f"[WARN] 列名验证结果保存失败: {e}")def analyze_data(file_path, config=None):    if config is None:        config = {}    lang = str(config.get('lang', 'JP')).strip().upper()    if lang in ['JA', 'JAPANESE', '日本語']:        lang = 'JP'    # 1. 加载和标准化数据    if 'preloaded_df' in config:        df = config['preloaded_df']    else:        df = load_and_preprocess_data(file_path)    col_name_maps = config.get("col_name_maps") or {}    canon2raw = col_name_maps.get("canon2raw") or {}    if not canon2raw:        canon2raw = {_canon_col_name(c): c for c in df.columns}    # 优先使用 GUI 传来的映射；没有就从当前 df.columns 现场构造    col_name_maps = config.get("col_name_maps") or {}    canon2raw = col_name_maps.get("canon2raw") or {}    if not canon2raw:        canon2raw = {_canon_col_name(c): c for c in df.columns}    time_col = config.get('time_col')  # 可能在后面会用到    # ===== 初始化 unit_map_hint，保证后面不报错 =====    unit_map_hint = {}    # ===== (1) 积算热量 MJ/GJ → 等效 kWh 预处理 =====    try:        THERMAL_HINT = re.compile(r"(積算熱量|heat\s*energy|冷房積算|暖房積算)", flags=re.IGNORECASE)        for col in list(df.columns):            if THERMAL_HINT.search(str(col)):                unit = str(unit_map_hint.get(col, "")).lower() if isinstance(unit_map_hint, dict) else ""                s = pd.to_numeric(df[col], errors="coerce")                if "gj" in unit:                    df[col] = s * 277.7777777778  # GJ → kWh                    unit_map_hint[col] = "kWh(eq)"                elif "mj" in unit:                    df[col] = s * 0.2777777777778  # MJ → kWh                    unit_map_hint[col] = "kWh(eq)"    except Exception as e:        print(f"[WARN] MJ/GJ → kWh 转换失败: {e}")    # ===== 安全包装 register_role_callback，避免报错 =====    def _register_role(col_name: str, role: str):        if "register_column_role" in globals() and callable(globals()["register_column_role"]):            try:                globals()["register_column_role"](col_name, role)            except Exception:                pass    # ===== (2) 累计电量 / 热量 → 瞬时功率(kW) 预处理 =====    try:        # 先跑“泛化版”（兼容累计表计 & 分段能量/日算値）        df = add_power_columns_from_energy_generic(            df=df,            time_col=None,  # 如已识别具体时间列可传入            unit_map=unit_map_hint,        )        # 再跑“只认累计表计”的老函数（保持向后兼容）        _res = add_power_columns_from_cumulative_energy(            df=df,            time_col=None,            unit_map=unit_map_hint,            register_role_callback=_register_role,            name_mutation="auto"        )        if isinstance(_res, tuple) and len(_res) >= 1:            df = _res[0]            created_power_cols = _res[1] if len(_res) > 1 else []        else:            df = _res            created_power_cols = []        if created_power_cols:            print(f"[PRE] Derived power columns: {created_power_cols}")    except Exception as e:        print(f"[WARN] energy→power 预处理失败: {e}")    # 2. 物理角色判定    role_dict, ai_roles, slot_details = batch_physical_role_review(df, client)    # print("[INFO] 字段物理角色判定-人工review:", role_dict)    # 单位推测    unit_db = batch_guess_units(df, role_dict, client)    # print("[INFO] 字段单位智能判定:", unit_db)    try:        df = add_power_columns_from_energy_generic(            df=df,            time_col=None,  # 若你已识别具体时间列，可填名字            unit_map=unit_db  # 关键：这里用 unit_db 而不是 unit_map_hint        )        print("[POST] generic 能量→功率（基于 unit_db）已执行")    except Exception as e:        print(f"[WARN] generic 能量→功率（基于 unit_db）失败: {e}")    ai_result = ai_batch_categorize_columns(list(df.columns), client)    if isinstance(ai_result, dict) and ai_result:        # 只把 AI 判定的非 'other' 写回，避免覆盖掉 batch_physical_role_review 里的有效标签（含 power_accum）        merged = dict(role_dict)  # 以本地 AI+兜底为底        for k, v in ai_result.items():            if v and v != 'other':                merged[k] = v        role_dict = merged    else:        print("[WARNING] AI批量分类失败/为空，继续用人工review的role_dict。")        # role_dict 保持为人工review结果    related_columns = find_related_columns(role_dict, group_mode='ai', client=client, lang=lang)    report_group_cop_capability(related_columns, role_dict)    # 后续你可以像这样提取出各类字段，比如（你可以批量处理，也可以分组处理）：    supply_temp_cols = [col for col, role in role_dict.items() if                        role in ["heat_source_supply_temp", "terminal_supply_air_temp"]]    return_temp_cols = [col for col, role in role_dict.items() if                        role in ["heat_source_return_temp", "terminal_return_air_temp"]]    flow_cols = [col for col, role in role_dict.items() if role in ["heat_source_flow", "terminal_air_volume"]]    power_cols = [col for col, role in role_dict.items() if role in ["heat_source_power", "terminal_power"]]    capacity_cols = [col for col, role in role_dict.items() if role in ["heat_source_capacity", "terminal_capacity"]]    print("[DEBUG] 各类字段:", {        "supply_temp": supply_temp_cols,        "return_temp": return_temp_cols,        "flow": flow_cols,        "power": power_cols,        "capacity": capacity_cols,    })    try:        # 可以允许从 config 覆盖输出目录，否则用默认路径        col_val_dir = config.get(            "column_validation_dir",            r"D:\dynamoFile\PythonScript\LLM\output\column_name_validation"        )        save_column_name_validation(role_dict, out_dir=col_val_dir)    except Exception as e:        print(f"[WARN] 保存列名验证 txt 失败: {e}")    # 4. 负荷率分析    cooling_capacity_dict = None    if config.get('cooling_capacity') is not None:        cooling_capacity_dict = {k: config['cooling_capacity'] for k in related_columns.keys()}    weather_df = config.get('weather_df')    load_results = analyze_load_ratio_multiunit(        df, related_columns,        cooling_capacity_dict=cooling_capacity_dict,        lang=lang,        weather_df=config.get('weather_df'),        weather_time_col='timestamp',        unit_db=unit_db,        client=client,        role_dict=role_dict,        ai_roles=ai_roles,        slot_details=slot_details,        canon2raw=canon2raw,    )    # 5. COP分析    cop_results = {}    unit_combo_scores = []    for group_name, group_info in related_columns.items():        terminal_cop_result = None        heat_source_cop_result = None        cols = group_info['columns']        group_roles = {col: role_dict.get(col, "") for col in cols}        needed = ["heat_source_supply_temp", "heat_source_return_temp", "heat_source_flow", "heat_source_power"]        if not all(v in group_roles.values() for v in needed):            print(f"[SKIP] {group_name} 字段不全，缺: {[v for v in needed if v not in group_roles.values()]}")            continue        # 热源字段        heat_source_supply_temp_col = next((c for c, r in group_roles.items() if r == "heat_source_supply_temp"), None)        heat_source_return_temp_col = next((c for c, r in group_roles.items() if r == "heat_source_return_temp"), None)        heat_source_flow_col = next((c for c, r in group_roles.items() if r == "heat_source_flow"), None)        heat_source_power_col = next((c for c, r in group_roles.items() if r == "heat_source_power"), None)        heat_source_supply_temp_col = resolve_col_name(heat_source_supply_temp_col,df, canon2raw)        heat_source_return_temp_col = resolve_col_name(heat_source_return_temp_col,df, canon2raw)        heat_source_flow_col = resolve_col_name(heat_source_flow_col,df, canon2raw)        heat_source_power_col = resolve_col_name(heat_source_power_col,df, canon2raw)        # print(f"\n====【{group_name} 物理量关键字段自动识别结果】====")        for label, col in [            ("供水温度", heat_source_supply_temp_col),            ("回水温度", heat_source_return_temp_col),            ("流量", heat_source_flow_col),            ("功率", heat_source_power_col)        ]:            # print(f"[字段识别] {label} 列名: {col}")            if col:                series = df[col]                print(f"  - 原始前10: {series.head(10).tolist()}")                print(f"  - 非零非空前10: {first_n_valid(series)}")            else:                print(f"  - 无数据列")        print("-" * 50)        if all([heat_source_supply_temp_col, heat_source_return_temp_col, heat_source_flow_col, heat_source_power_col]):            supply = df[heat_source_supply_temp_col]            return_ = df[heat_source_return_temp_col]            flow = df[heat_source_flow_col]            power = df[heat_source_power_col]            valid_dbg_idx = _pick_valid_indices_for_sampling(flow, power, supply - return_, max_n=200)            print(f"[DEBUG] 原始样本(有效片段): "                  f"supply: {list(supply.loc[valid_dbg_idx].head(20).astype(float))} "                  f"return: {list(return_.loc[valid_dbg_idx].head(20).astype(float))} "                  f"flow: {list(flow.loc[valid_dbg_idx].head(20).astype(float))} "                  f"power: {list(power.loc[valid_dbg_idx].head(20).astype(float))}")        # 末端字段        terminal_supply_air_temp_col = next((c for c, r in group_roles.items() if r == "terminal_supply_air_temp"),                                            None)        terminal_return_air_temp_col = next((c for c, r in group_roles.items() if r == "terminal_return_air_temp"),                                            None)        terminal_air_volume_col = next((c for c, r in group_roles.items() if r == "terminal_air_volume"), None)        terminal_power_col = next((c for c, r in group_roles.items() if r == "terminal_power"), None)        terminal_capacity_col = next((c for c, r in group_roles.items() if r == "terminal_capacity"), None)        terminal_supply_air_temp_col = resolve_col_name(terminal_supply_air_temp_col,df, canon2raw)        terminal_return_air_temp_col = resolve_col_name(terminal_return_air_temp_col,df, canon2raw)        terminal_air_volume_col = resolve_col_name(terminal_air_volume_col,df, canon2raw)        terminal_power_col = resolve_col_name(terminal_power_col,df, canon2raw)        terminal_capacity_col = resolve_col_name(terminal_capacity_col,df, canon2raw)        # === 末端COP分析 ===        terminal_cop_result = None        if all([terminal_supply_air_temp_col, terminal_return_air_temp_col, terminal_air_volume_col, terminal_power_col]):            try:                cop_df = calc_terminal_cop(                    df,                    terminal_return_air_temp_col,  # 入口温度                    terminal_supply_air_temp_col,  # 出口温度                    terminal_air_volume_col,  # 风量                    terminal_power_col                )                cop_terminal = cop_df['COP_valid']                stats_terminal = {                    'cop_mean': cop_terminal.mean(),                    'cop_max': cop_terminal.max(),                    'cop_min': cop_terminal.min(),                    'cop_std': cop_terminal.std(),                    'high_cop_percentage': (cop_terminal > 5).mean() * 100,                    'low_cop_percentage': (cop_terminal < 2).mean() * 100                }                terminal_cop_result = {                    "cop_stats": stats_terminal,                    "cop_data": cop_terminal,                    "columns_used": [                        terminal_supply_air_temp_col,                        terminal_return_air_temp_col,                        terminal_air_volume_col,                        terminal_power_col                    ],                    "method": "terminal"                }                print(f"[INFO] {group_name} 末端COP计算完成:", stats_terminal)            except Exception as e:                print(f"[ERROR] {group_name} 末端COP计算出错: {e}")        # === 热源COP分析（单位组合全枚举 + AI置信度打分自动选最佳）===        heat_source_cop_result = None        if all([heat_source_supply_temp_col, heat_source_return_temp_col, heat_source_flow_col, heat_source_power_col]):            if not all(x in df.columns for x in                       [heat_source_supply_temp_col, heat_source_return_temp_col, heat_source_flow_col,                        heat_source_power_col]):                heat_source_cop_result = None            else:                combo_result = guess_best_unit_combo_with_retry(                    df,                    heat_source_supply_temp_col,                    heat_source_return_temp_col,                    heat_source_flow_col,                    heat_source_power_col,                    unit_db,                    client                )                # 判断AI是否找到了合理的单位组合                if combo_result and combo_result.get("unit_combo"):                    best_flow_unit, best_power_unit = combo_result["unit_combo"].split("+")                    valid_flow_units = {"m3/h", "m³/h", "L/s", "L/min", "l/s", "l/min"}                    valid_power_units = {"kW", "W", "kw", "w"}                    if str(best_flow_unit).strip() not in valid_flow_units:                        print(f"[SKIP] {group_name} 热源COP跳过：flow_unit={best_flow_unit} 不在允许范围")                        heat_source_cop_result = None                        continue                    if str(best_power_unit).strip() not in valid_power_units:                        print(f"[SKIP] {group_name} 热源COP跳过：power_unit={best_power_unit} 不在允许范围")                        heat_source_cop_result = None                        continue                    flow = convert_flow(df[heat_source_flow_col], best_flow_unit)                    power = convert_power(df[heat_source_power_col], best_power_unit)                    delta_t = (df[heat_source_return_temp_col] - df[heat_source_supply_temp_col]).abs()                    cooling_power = flow * 4.18 * delta_t                    valid = (power > 0.05) & flow.notna() & delta_t.notna() & (delta_t > 0.05)                    cop = cooling_power[valid] / power[valid]                    cop = cop.replace([np.inf, -np.inf], np.nan)                    # 加入合理COP过滤                    cop_valid = filter_valid_cop(cop, min_cop=0.5, max_cop=15)                    print("COP非空样本:", cop_valid[cop_valid.notna()].head(10).tolist())                    stats = {                        'cop_mean': cop_valid.mean(),                        'cop_max': cop_valid.max(),                        'cop_min': cop_valid.min(),                        'cop_std': cop_valid.std(),                        'high_cop_percentage': (cop_valid > 5).mean() * 100,                        'low_cop_percentage': (cop_valid < 2).mean() * 100,                        'n_valid': cop_valid.notna().sum()                    }                    heat_source_cop_result = {                        "cop_stats": stats,                        "cop_data": cop_valid,  # 只用合理COP                        "columns_used": [                            heat_source_supply_temp_col,                            heat_source_return_temp_col,                            heat_source_flow_col,                            heat_source_power_col                        ],                        "flow_unit": best_flow_unit,                        "power_unit": best_power_unit,                        "ai_confidence": combo_result.get("confidence", None),                        "ai_reason": combo_result.get("reason", ""),                        "method": "heat_source_combo_ai"                    }                    print(                        f"[INFO] {group_name} 热源COP-单位组合AI判定: {best_flow_unit}+{best_power_unit}, 置信度: {combo_result.get('confidence', 0)}, 结果:",                        stats)                else:                    print(f"[WARN] {group_name} 热源COP所有单位组合AI都无法置信（AI得分低或数据异常），请人工检查数据！")                    heat_source_cop_result = None        # === 后续cop_reports、unit_combo_scores等的处理不用改 ===        # === GPT分析（可按两种COP分别做）===        cop_reports = {}        for tag, result in [("末端COP", terminal_cop_result), ("热源COP", heat_source_cop_result)]:            if result is None:                # 不跳过！输出一个N/A分析                if lang == 'JP':                    report = f"{group_name} の{tag}はデータ不足のため計算できません。"                else:                    report = f"{group_name} {tag}因数据不足无法计算。"                cop_reports[tag] = report                continue            stats = result["cop_stats"]            if lang == 'JP':                if not isinstance(stats, dict):                    stats = {}                prompt = (                    f"{group_name} の{tag}分析結果:\n"                    f"平均COP: {safe_fmt(stats['cop_mean'], '.2f')}\n"                    f"最大COP: {safe_fmt(stats['cop_max'], '.2f')}\n"                    f"最低COP: {safe_fmt(stats['cop_min'], '.2f')}\n"                    f"標準偏差: {safe_fmt(stats['cop_std'], '.2f')}\n"                    f"高効率時間割合(COP>5): {safe_fmt(stats['high_cop_percentage'], '.1f')}%\n"                    f"低効率時間割合(COP<2): {safe_fmt(stats['low_cop_percentage'], '.1f')}%\n\n"                    "この結果について、専門的に分かりやすく要点ごとに解説してください。"                )            elif lang == "EN":                prompt = (                    f"{group_name} {tag} results:\n"                    f"Mean COP: {safe_fmt(stats.get('cop_mean'), '.2f')}\n"                    f"Max COP: {safe_fmt(stats.get('cop_max'), '.2f')}\n"                    f"Min COP: {safe_fmt(stats.get('cop_min'), '.2f')}\n"                    f"Std. deviation: {safe_fmt(stats.get('cop_std'), '.2f')}\n"                    f"High-efficiency share (COP>5): {safe_fmt(stats.get('high_cop_percentage'), '.1f')}%\n"                    f"Low-efficiency share (COP<2): {safe_fmt(stats.get('low_cop_percentage'), '.1f')}%\n\n"                    "Write an operator-facing analysis in clear bullet points:\n"                    "• explain what these numbers indicate;\n"                    "• highlight when performance is good/poor and why;\n"                    "• suggest 2–3 likely causes (e.g., short-cycling, flow mismatch, sensor issues);\n"                    "• list 2–3 recommended checks or follow-ups."                )            else:                prompt = (                    f"{group_name} {tag}分析结果:\n"                    f"平均COP: {safe_fmt(stats['cop_mean'], '.2f')}\n"                    f"最大COP: {safe_fmt(stats['cop_max'], '.2f')}\n"                    f"最低COP: {safe_fmt(stats['cop_min'], '.2f')}\n"                    f"标准差: {safe_fmt(stats['cop_std'], '.2f')}\n"                    f"高效时间比例(COP>5): {safe_fmt(stats['high_cop_percentage'], '.1f')}%\n"                    f"低效时间比例(COP<2): {safe_fmt(stats['low_cop_percentage'], '.1f')}%\n\n"                    "请按要点、用专业但易懂的语言分析本COP结果。"                )            resp = client.chat.completions.create(                model="gpt-4o",                messages=[                    {"role": "system", "content": "你是一个HVAC系统专家，能够分析系统能效特性"},                    {"role": "user", "content": prompt}                ]            )            report = resp.choices[0].message.content            result["cop_report"] = report            print(f"\n[INFO] {group_name} {tag} GPT分析报告：\n", report)            cop_reports[tag] = report        # === 汇总到结果 ===        cop_results[group_name] = {            "terminal_cop": terminal_cop_result,            "heat_source_cop": heat_source_cop_result,            "cop_reports": cop_reports,        }        try:            if all([heat_source_supply_temp_col, heat_source_return_temp_col, heat_source_flow_col,                    heat_source_power_col]):                combo_result = guess_best_unit_combo_with_retry(                    df,                    heat_source_supply_temp_col,                    heat_source_return_temp_col,                    heat_source_flow_col,                    heat_source_power_col,                    unit_db,                    client                )                if isinstance(combo_result, dict):                    unit_combo_scores.append({                        **combo_result,                        "group_name": group_name,                        "supply_col": heat_source_supply_temp_col,                        "return_col": heat_source_return_temp_col,                        "flow_col": heat_source_flow_col,                        "power_col": heat_source_power_col,                    })                elif isinstance(combo_result, list):                    for item in combo_result:                        if isinstance(item, dict):                            unit_combo_scores.append({                                **item,                                "group_name": group_name,                                "supply_col": heat_source_supply_temp_col,                                "return_col": heat_source_return_temp_col,                                "flow_col": heat_source_flow_col,                                "power_col": heat_source_power_col,                            })        except Exception as e:            print(f"[unit_combo_scores自动评分异常][{group_name}] {e}")    # 全部机组循环结束后再 return！    return {        "cop_analysis": cop_results,        "load_analysis": load_results,        "unit_db": unit_db,        "unit_combo_scores": unit_combo_scores,        # 实验用：列识别结果        "ai_roles": ai_roles,        "slot_details": slot_details,        "role_dict": role_dict,        "related_columns": related_columns,    }def report_group_cop_capability(related_columns, role_dict):    """    输出每个分组内能不能算COP/末端COP，缺少哪些物理量，友好展示。    """    # COP 只需要 4 要素；capacity 不应作为“是否能算 COP”的硬性条件    required_heat_source = ['heat_source_supply_temp', 'heat_source_return_temp', 'heat_source_flow',                            'heat_source_power']    required_terminal = ['terminal_supply_air_temp', 'terminal_return_air_temp', 'terminal_air_volume', 'terminal_power']    for group, info in related_columns.items():        cols = info["columns"]        roles = {col: role_dict.get(col, "") for col in cols}        missing_hs = [k for k in required_heat_source if k not in roles.values()]        missing_tm = [k for k in required_terminal if k not in roles.values()]        print(f"\n【分组: {group}】")        print("  全部字段物理量：", roles)        if not missing_hs:            print("  ✓ 可直接计算【热源COP】")        else:            print(f"  × 无法算【热源COP】，缺: {missing_hs}")        if not missing_tm:            print("  ✓ 可直接计算【末端COP】")        else:            print(f"  × 无法算【末端COP】，缺: {missing_tm}")def analyze_operation_status(df, related_columns, lang='JP'):    """分析机组运行状态并生成报告"""    analysis_results = {}    for group_name, group_info in related_columns.items():        if 'Unit_' not in group_name:  # 只分析机组数据            continue        unit_cols = group_info['columns']        unit_data = df[unit_cols].describe().to_dict()        try:            if lang == 'JP':                prompt = (                    f"以下のHVACユニット({group_name})の運転データを分析してください:\n"                    f"{json.dumps(unit_data, ensure_ascii=False)}\n\n"                    "以下の点に注目して分析してください:\n"                    "1. 温度、流量、電力などの主要パラメータの統計的特徴\n"                    "2. 異常値や外れ値の可能性\n"                    "3. エネルギー効率に関する所見\n"                    "4. 改善可能な点\n"                    "5. 全体的な運転状態の評価\n\n"                    "専門的ですが分かりやすい日本語で、箇条書きで報告してください。"                )            else:                prompt = (                    f"请分析以下HVAC机组({group_name})的运行数据:\n"                    f"{json.dumps(unit_data, ensure_ascii=False)}\n\n"                    "请关注以下方面:\n"                    "1. 温度、流量、电力等主要参数的统计特征\n"                    "2. 异常值或离群值的可能性\n"                    "3. 关于能源效率的观察\n"                    "4. 可能的改进点\n"                    "5. 整体运行状态评估\n\n"                    "请使用专业但易懂的中文，以项目符号列表形式报告。"                )            response = client.chat.completions.create(                model="gpt-4o",                messages=[{                    "role": "system",                    "content": "你是一个HVAC系统专家，能够从数据中识别运行模式和问题"                }, {                    "role": "user",                    "content": prompt                }]            )            analysis_results[group_name] = response.choices[0].message.content        except Exception as e:            print(f"机组分析失败({group_name}): {e}")            analysis_results[group_name] = "分析不可用"    return analysis_resultsdef export_to_word(        explanations, column_info, operation_analysis=None, lang='JP', output_path="hvac_report.docx"):    # print("【EXPORT_TO_WORD】explanations:", explanations)    # print("【EXPORT_TO_WORD】column_info:", column_info)    print("【EXPORT_TO_WORD】operation_analysis:", operation_analysis)    print("【EXPORT_TO_WORD】output_path:", output_path)    # === 加入调试检查 ===    for k, v in explanations.items():        if v is None or (isinstance(v, float) and pd.isna(v)):            print(f"[WARNING] explanations[{k}] 为 None 或 NaN")        if not isinstance(v, str):            print(f"[WARNING] explanations[{k}] 不是 str, 实际类型: {type(v)}")    # ==================    """生成Word报告"""    try:        # 判断output_path是否带目录，如果有目录则确保目录存在        out_dir = os.path.dirname(output_path)        if out_dir and out_dir.strip() != "":            os.makedirs(out_dir, exist_ok=True)        doc = Document()        # 添加标题        title = 'HVACデータ分析レポート' if lang == 'JP' else 'HVAC Data Analysis Report'        title_para = doc.add_heading(title, level=0)        title_para.alignment = WD_PARAGRAPH_ALIGNMENT.CENTER        # 添加创建日期        date_format = '%Y年%m月%d日' if lang == 'JP' else '%Y-%m-%d'        doc.add_paragraph(datetime.now().strftime(date_format))        doc.add_paragraph()        # 添加分类表格        section_title = '列名分類' if lang == 'JP' else 'Column Classification'        doc.add_heading(section_title, level=1)        # 创建表格        table = doc.add_table(rows=1, cols=3)        table.style = 'Table Grid'  # 常用的样式，若报错可换为 'Light Grid'        # 表头        hdr_cells = table.rows[0].cells        headers = ['列名', '分類', '説明'] if lang == 'JP' else ['Column', 'Category', 'Description']        for i, header in enumerate(headers):            hdr_cells[i].text = header            if hdr_cells[i].paragraphs[0].runs:                hdr_cells[i].paragraphs[0].runs[0].font.bold = True        # 添加数据行        for col, exp in explanations.items():            row_cells = table.add_row().cells            row_cells[0].text = str(col)            row_cells[1].text = column_info.get(col, '不明' if lang == 'JP' else 'Unknown')            row_cells[2].text = exp if exp else "-"        # 添加运行分析部分        if operation_analysis:            analysis_title = '運転状態分析' if lang == 'JP' else 'Operation Analysis'            doc.add_heading(analysis_title, level=1)            for unit, analysis in operation_analysis.items():                doc.add_heading(unit, level=2)                for line in analysis.split('\n'):                    if line.strip():  # 跳过空行                        doc.add_paragraph(line.strip())        # 保存文档        doc.save(output_path)        print(f"Word报告已保存到: {output_path}")        return output_path    except Exception as e:        print(f"Word报告生成失败: {e}")        import traceback        traceback.print_exc()        raise    finally:        print("[EXPORT TO WORD FINISHED]")# 辅助函数def load_and_preprocess_data(file_path):    if file_path.endswith('.csv'):        df = pd.read_csv(file_path)    else:        df = pd.concat(pd.read_excel(file_path, sheet_name=None).values(), ignore_index=True)    df = normalize_column_names(df)    if time_cols := identify_time_columns(df):        idx = pd.to_datetime(df[time_cols[0]], errors="coerce")        df = df.set_index(idx)        df = df.sort_index()        # ★ 关键：同一时间戳保留最后一条（你也可以换成 keep='first' 或汇总）        df = df[~df.index.duplicated(keep='last')]    return df#  单位推测部分（测试ingdef ai_guess_unit(col_name, sample_values, client, lang="zh"):    prompt = (        f"你是暖通工程数据专家。请根据字段名与样本数据，判断该字段在实际HVAC项目中最可能的物理单位，"        f"以样本值的数值分布/大小/精度为主，不要只看字段名；若明显不符常规单位请指出。"        f"\n字段名: {col_name}"        f"\n样本值: {sample_values[:1000]}"        f"\n请只输出**有效的标准 JSON（双引号）**："        f"{{\"unit\": \"xxx\", \"reason\": \"xxx\", \"convert_tip\": \"xxx\"}}"    )    resp = client.chat.completions.create(        model="gpt-4o",        messages=[            {"role": "system", "content": "你是HVAC物理量单位专家。只输出有效的标准 JSON。"},            {"role": "user", "content": prompt}        ],        temperature=0.1,        max_tokens=256,    )    return robust_json_parse(resp.choices[0].message.content)def batch_guess_units(df, role_dict, client, sample_n=10):    """    针对所有已判定物理角色的列，批量AI推断单位    返回: {col: {"unit":..., "reason":..., "convert_tip":...}}    """    unit_db = {}    for col, role in role_dict.items():        if role == "other" or col not in df.columns:            continue        values = df[col].dropna().tolist()        sample = smart_nonzero_sample(values)   # 只采非零样本        if not sample:            print(f"[WARNING] {col} 全为零或空，无法AI判单位")            continue        unit_info = ai_guess_unit(col, sample, client)        print(f"[AI单位判定] {col}: {unit_info.get('unit', 'unknown')}")        unit_db[col] = unit_info    return unit_dbdef slot_unit_infer(col_name, series):    """    面向 hvac_power_col_memory.C6 的单位推断适配器:    输入:  列名 + pandas Series（这一列的数据）    输出: {"unit": "...", "confidence": float}    内部调用 ai_guess_unit + smart_nonzero_sample    """    try:        # 转成数值方便过滤        values = pd.to_numeric(series, errors="coerce").dropna().tolist()    except Exception:        # 万一 series 不是标准 Series，再兜底一次        values = pd.Series(series).dropna().tolist()    sample = smart_nonzero_sample(values)    if not sample:        return {"unit": None, "confidence": 0.0}    info = ai_guess_unit(col_name, sample, client)    unit = (info or {}).get("unit")    if not unit:        return {"unit": None, "confidence": 0.0}    # 置信度目前先给个固定值；你以后可以根据样本量 / 规则细化    return {"unit": unit, "confidence": 0.8}def ai_score_unit_combos(supply, return_, flow_raw, power_raw, combos, client, sys_type="冷水机组"):    combo_results = []    for combo in combos:        try:            flow = convert_flow(flow_raw, combo["flow_unit"])            power = convert_power(power_raw, combo["power_unit"])            delta_t = supply - return_            cooling_power = flow * 4.18 * delta_t            power_safe = power.replace(0, np.nan)            cop = (cooling_power / power_safe).replace([np.inf, -np.inf], np.nan)            combo_results.append({                "unit_combo": f"{combo['flow_unit']}+{combo['power_unit']}",                "cop": list(pd.Series(cop).dropna().head(20)),  # 传样本切片给 LLM 即可                "confidence": None,                "reason": None            })        except Exception as e:            print(f"[单位组合换算异常] {combo}: {e}")    prompt = (            "你是建筑暖通数据专家。对下列冷水机组数据在不同单位组合下的 COP 样本，"            "判断哪些组合最可能真实、合理；请对每组给出 0-1 的置信度并解释。"            "只输出**标准 JSON（双引号）**数组："            "[{\"unit_combo\":\"...\",\"cop\":[...],\"confidence\":0.x,\"reason\":\"...\"}, ...]。数据：\n"            + json.dumps(combo_results, ensure_ascii=False)    )    resp = client.chat.completions.create(        model="gpt-4o",        messages=[            {"role": "system", "content": "你是HVAC数据单位与能效诊断专家。只输出有效的标准 JSON。"},            {"role": "user", "content": prompt}        ],        temperature=0.0,        max_tokens=1024,    )    return robust_json_parse(resp.choices[0].message.content)def convert_flow(series, unit):    """    将各种来路的流量统一换算成 L/s（规范单位）    这样 Q[kW] = 4.18 * (L/s) * ΔT 就成立，无需改 4.18 系数    """    if unit == "L/s":        return series    elif unit == "L/min":        return series / 60.0           # L/min -> L/s    elif unit == "m³/h":        return series * (1000.0/3600.0)  # m³/h -> L/s  (=0.277778)    elif unit == "L/h":        return series / 3600.0         # L/h -> L/s    else:        # 不识别就原样返回（尽量别走到这里）        return seriesdef convert_power(series, unit):    if unit == "kW":        return series    elif unit == "W":        return series / 1000    else:        return seriesdef _build_weighted_sample_view(supply_n, return_n, flow_n, power_n, max_n=5000):    """    从“整列数据”构建一个带权重的样本视图：    - 所有行都参与权重计算；    - 但只抽取 <= max_n 行用来算 COP / 评分；    - 权重大、质量好的行更容易被选中。    返回: supply_s, return_s, flow_s, power_s    """    # 1) 先过滤掉 NaN，其他一律保留参与权重计算    mask_valid = (~supply_n.isna()) & (~return_n.isna()) & (~flow_n.isna()) & (~power_n.isna())    if mask_valid.sum() == 0:        # 没有任何可用数据，返回空        return (            supply_n.iloc[[]],            return_n.iloc[[]],            flow_n.iloc[[]],            power_n.iloc[[]],        )    s = supply_n[mask_valid]    r = return_n[mask_valid]    f = flow_n[mask_valid]    p = power_n[mask_valid]    n = len(s)    idx = np.arange(n)    # 2) 构建权重：所有行都有权重，但“好样本”权重大    #   - 基础权重：0.2（非运行区也有一点点权重）    #   - 运行中（flow>0, power>0）：1.0    #   - 运行中且 ΔT 合理（比如 1~25℃）：3.0    w = np.full(n, 0.2, dtype=float)    run_mask = (f > 0) & (p > 0)    deltaT = (s - r).abs()    nice_delta = deltaT.between(1, 25)  # 你可以根据冷热水机组类型微调这个范围    w[run_mask] = 1.0    w[run_mask & nice_delta] = 3.0    # 如果数据量不大，直接全列使用    if n <= max_n:        return s, r, f, p    # 3) 加权抽样（无随机数，保证“稳定可复现”）    #   - 先按权重从大到小排序    #   - 取前 70% 的名额给“高权重样本”    #   - 剩下 30% 在低权重区域里均匀抽取，保证全局覆盖    order = np.argsort(-w)  # 按权重降序    k_high = int(max_n * 0.7)    if k_high < 1:        k_high = 1    high_idx = order[:k_high]    remaining = order[k_high:]    k_low = max_n - len(high_idx)    if k_low > 0 and len(remaining) > 0:        # 在剩下的 idx 里做“均匀抽样”（不随机，用步长采样，保证稳定）        step = max(1, len(remaining) // k_low)        low_idx = remaining[::step][:k_low]        chosen = np.concatenate([high_idx, low_idx])    else:        chosen = high_idx    # 去重 & 排序，避免乱序    chosen = np.unique(chosen)    s2 = s.iloc[chosen]    r2 = r.iloc[chosen]    f2 = f.iloc[chosen]    p2 = p.iloc[chosen]    return s2, r2, f2, p2def guess_best_unit_combo_with_retry(    df, supply_col, return_col, flow_col, power_col, unit_db, client,    min_confidence=0.5, fallback_units=None, max_retry=2):    """    先用 AI 的单位作为先验，计算并打分；若不达标则全组合穷举打分；    若找到更优组合则采用；并加“粘性”机制避免来回抖动。    返回 dict: {        "unit_combo": "L/s+kW",        "flow_unit": "...",        "power_unit": "...",        "cop": Series, "cop_mean":..., "cop_std":..., "n_valid":...,        "confidence": float, "reason": str    } 或 None    """    FLOW_UNIT_LIST = ['m³/h', 'L/min', 'L/h', 'L/s']    POWER_UNIT_LIST = ['kW', 'W']    # —— 使用“整列 + 权重加权”的方式构建样本视图 ——    supply = df[supply_col]; return_ = df[return_col]    flow_raw = df[flow_col]; power_raw = df[power_col]    supply_n = pd.to_numeric(supply, errors='coerce')    return_n = pd.to_numeric(return_, errors='coerce')    flow_n = pd.to_numeric(flow_raw, errors='coerce')    power_n = pd.to_numeric(power_raw, errors='coerce')    # 全列都参与权重计算，在内部做带权抽样（最多 5000 行）    supply_s, return_s, flow_s, power_s = _build_weighted_sample_view(        supply_n, return_n, flow_n, power_n, max_n=5000    )    if len(supply_s) == 0:        print(f"[WARNING] 无法从整列中构建任何有效样本: {flow_col} + {power_col}")        return None    # —— 先验：AI 猜的单位 ——    ai_flow_unit  = unit_db.get(flow_col, {}).get('unit')    ai_power_unit = unit_db.get(power_col, {}).get('unit')    ai_combo = None    if ai_flow_unit in FLOW_UNIT_LIST and ai_power_unit in POWER_UNIT_LIST:        f = convert_flow(flow_s, ai_flow_unit)        p = convert_power(power_s, ai_power_unit)        ai_score, ai_stats, ai_cop = _score_unit_combo(supply_s, return_s, f, p)        ai_combo = {            "flow_unit": ai_flow_unit, "power_unit": ai_power_unit,            "score": ai_score, "stats": ai_stats, "cop": ai_cop,            "reason": "AI先验单位通过本地规则评估"        }    # —— 组合候选：先把 AI 的放前面评估，然后所有主流组合都评估一遍 ——    combos = []    if ai_combo:        combos.append(ai_combo)    for fu in FLOW_UNIT_LIST:        for pu in POWER_UNIT_LIST:            if ai_combo and fu == ai_combo["flow_unit"] and pu == ai_combo["power_unit"]:                continue            f = convert_flow(flow_s, fu)            p = convert_power(power_s, pu)            score, cstats, ccop = _score_unit_combo(supply_s, return_s, f, p)            combos.append({                "flow_unit": fu, "power_unit": pu, "score": score, "stats": cstats, "cop": ccop,                "reason": "全组合穷举评估"            })    # —— 选分数最高的 ——    if not combos:        print(f"[WARNING] 组合评估为空：{flow_col} + {power_col}")        return None    best = max(combos, key=lambda x: x["score"])    # —— 粘性：如果缓存里已有旧选择，且新分数并没有高出 STICKINESS_DELTA，就继续沿用旧选择 ——    cache_key = (flow_col, power_col)    cached = UNIT_CHOICE_CACHE.get(cache_key)    if cached and (best["score"] < (cached.get("score", 0) + STICKINESS_DELTA)):        # 复用旧选择        fu, pu = cached["flow_unit"], cached["power_unit"]        f = convert_flow(flow_s, fu)        p = convert_power(power_s, pu)        score, cstats, ccop = _score_unit_combo(supply_s, return_s, f, p)        best = {"flow_unit": fu, "power_unit": pu, "score": score, "stats": cstats, "cop": ccop,                "reason": f"沿用缓存选择（新分数提升<{STICKINESS_DELTA}）"}    # —— 基本阈值：分数“看起来像样”再接受 ——    # （你也可以把阈值设为 0.55~0.65 之间，再结合 n_valid 下限）    if best["stats"].get("n_valid", 0) < 10 or best["score"] < 0.55:        # 可选：调用 LLM 在若干个次优组合中做 tie-break（当数据真的“难分”时）        # 这里保留最简单的本地规则，避免额外 API 时延/成本。        print(f"[WARN] 单位组合得分偏低或样本过少：score={best['score']:.2f}, n={best['stats'].get('n_valid',0)}。")        # 仍然返回 best，但在上层可以提示“人工复核”。        # === 复判：当本地评分偏低时，用 AI 在 Top-K 候选里二次判定 ===        try:            TOPK = 5            # 取分数最高的若干候选，把单位对传给 AI            top_candidates = sorted(combos, key=lambda x: x["score"], reverse=True)[:TOPK]            candidate_units = []            seen = set()            for c in top_candidates:                key = (c["flow_unit"], c["power_unit"])                if key in seen:                    continue                seen.add(key)                candidate_units.append({"flow_unit": c["flow_unit"], "power_unit": c["power_unit"]})            ai_rank = ai_score_unit_combos(                supply_s, return_s, flow_s, power_s,                candidate_units, client, sys_type="冷水机组"            )            if isinstance(ai_rank, list) and ai_rank:                # 选 AI 置信度最高的组合                ai_best = max(ai_rank, key=lambda x: float(x.get("confidence", 0) or 0))                unit_combo = ai_best.get("unit_combo", "")                if "+" in unit_combo:                    fu, pu = [t.strip() for t in unit_combo.split("+", 1)]                else:                    # 兜底：有些返回可能是 {'flow_unit':..., 'power_unit':...}                    fu = ai_best.get("flow_unit");                    pu = ai_best.get("power_unit")                if fu and pu:                    f2 = convert_flow(flow_s, fu)                    p2 = convert_power(power_s, pu)                    score2, stats2, cop2 = _score_unit_combo(supply_s, return_s, f2, p2)                    # 只要不比原 best 更差、且样本量够，就采用 AI 复判结果                    if stats2.get("n_valid", 0) >= 10 and score2 >= best["score"] - 1e-6:                        best = {                            "flow_unit": fu, "power_unit": pu,                            "score": float(score2), "stats": stats2, "cop": cop2,                            "reason": f"AI复判选择（confidence={ai_best.get('confidence', '?')}）"                        }                        print(f"[INFO] 复判采用: {fu} + {pu} | score={score2:.2f} | n={stats2.get('n_valid')}")        except Exception as e:            print(f"[复判失败] {e}")    # —— 写入缓存 ——    UNIT_CHOICE_CACHE[cache_key] = {        "flow_unit": best["flow_unit"], "power_unit": best["power_unit"],        "score": best["score"], "reason": best["reason"]    }    # —— 组织输出（和你原来结构一致） ——    fu = best["flow_unit"];    pu = best["power_unit"]    out = {        "unit_combo": f"{fu}+{pu}",        "flow_unit": fu, "power_unit": pu,        "cop": best["cop"],        "cop_mean": best["stats"].get("mean"),        "cop_std": best["stats"].get("std"),        "n_valid": best["stats"].get("n_valid"),        "confidence": float(min(1.0, best["score"])),  # 用分数当近似置信度        "reason": f"{best['reason']} | stats={best['stats']}"    }    # 防御：n_valid/mean/std 可能是 None/NaN，用 safe_fmt 打印    n_valid = int(out.get("n_valid") or 0)    mean_str = safe_fmt(out.get("cop_mean"), ".2f")    std_str = safe_fmt(out.get("cop_std"), ".2f")    print(        f"[单位自动判定] 最优组合: {fu} + {pu} | score={best['score']:.2f} | n={n_valid} | mean={mean_str} | std={std_str}")    return outdef filter_nonzero(values):    return [v for v in values if (isinstance(v, (int, float)) and v != 0) or            (isinstance(v, str) and v.strip() not in ['0', '0.0', '', None])]def filter_valid_cop(series, min_cop=0.5, max_cop=15):    """    过滤COP极端异常，只保留运行中合理样本（默认0.5~15）。    """    return series[(series > min_cop) & (series < max_cop)]def smart_nonzero_sample(values, n_head=20, n_tail=20, n_stride=5):    """    只取非零；用“等间隔抽样”代替随机，保证同一列每次采样一致，避免AI判单位抖动。    """    nonzero = filter_nonzero(values)    if not nonzero:        return []    L = len(nonzero)    head = nonzero[:n_head]    tail = nonzero[-n_tail:] if L > n_head else []    mid = nonzero[n_head: max(n_head, L - n_tail)]    mid_sample = mid[::max(1, n_stride)]    return head + list(mid_sample) + taildef _pick_valid_indices_for_sampling(flow, power, delta_t, max_n=2000):    """    返回用于取样/判定的一组“有效”行索引：    1) 优先选 power>0 & flow>0 & ΔT 非空    2) 若不足，再放宽到 power>0 & ΔT 非空    3) 再不足，放宽到 ΔT 非空    最后最多截取 max_n 行，避免超大数据拖慢    """    import numpy as np    idx_all = flow.index    mask1 = (power > 0) & (flow > 0) & delta_t.notna()    valid_idx = idx_all[mask1]    if len(valid_idx) < 50:        mask2 = (power > 0) & delta_t.notna()        valid_idx = idx_all[mask2]    if len(valid_idx) < 50:        mask3 = delta_t.notna()        valid_idx = idx_all[mask3]    if hasattr(valid_idx, 'to_series'):        valid_idx = valid_idx.to_series().head(max_n).index    else:        valid_idx = valid_idx[:max_n]    return valid_idxdef _score_unit_combo(supply_s, return_s, flow_s, power_s):    supply_s = pd.to_numeric(supply_s, errors='coerce')    return_s = pd.to_numeric(return_s, errors='coerce')    flow_s = pd.to_numeric(flow_s, errors='coerce')    power_s = pd.to_numeric(power_s, errors='coerce')    # 统一取 |ΔT|；避免因命名或工况（制冷/制热）导致符号翻转使COP为负    delta_t = (return_s - supply_s).abs()    valid = (power_s > 0.05) & delta_t.notna() & (delta_t > 0.05) & flow_s.notna()    if hasattr(valid, "to_numpy"):        valid = valid.to_numpy()    cop = (flow_s[valid] * 4.18 * delta_t[valid]) / power_s[valid]    cop = pd.Series(cop).replace([np.inf, -np.inf], np.nan)    cop_valid = cop[(cop > 0.5) & (cop < 15)]    n_valid = int(cop_valid.notna().sum())    if n_valid == 0:        return 0.0, {"n_valid": 0}, cop_valid    mean = float(cop_valid.mean())    std = float(cop_valid.std()) if n_valid > 1 else 0.0    # 目标均值 ~4，允许偏差；样本数越多越好；std 不宜过大    mean_score = max(0.0, 1.0 - abs(mean - 4.0) / 3.0)          # |mean-4|=3 时降到 0    size_score = min(1.0, n_valid / 60.0)                       # 60 个样本封顶    std_score  = max(0.0, 1.0 - max(0.0, std - 1.5) / 3.0)      # std>1.5 开始扣分    # “中段高效”占比（2~7）    mid_ratio  = float(((cop_valid >= 2.0) & (cop_valid <= 7.0)).mean()) if n_valid else 0.0    score = 0.45 * mean_score + 0.30 * size_score + 0.15 * std_score + 0.10 * mid_ratio    stats = {        "n_valid": n_valid, "mean": mean, "std": std,        "mid_ratio": mid_ratio, "mean_score": mean_score, "size_score": size_score, "std_score": std_score    }    return float(score), stats, cop_valid# === New: cumulative-energy -> power(kW) converter (project-agnostic) ===_CUMU_ENERGY_NAME_HINTS = re.compile(    r"(?:\benergy\b|積算|電力量|kwh|wh|mwh|累计|累積)",    flags=re.IGNORECASE)_TIME_NAME_HINTS = re.compile(    r"(time|date|datetime|timestamp|時|日|分|秒)", re.IGNORECASE)def _auto_pick_time_series(df: pd.DataFrame, time_col: Optional[str]) -> pd.Series:    """    选择时间序列（优先使用传入 time_col；否则自动识别）。    - 自动识别策略：从列名里匹配 time/date/時/日 等；逐个尝试解析为 datetime。    - 若 DataFrame 索引本身是 DatetimeIndex，则直接使用索引。    - 返回一个 Series，index 与 df 对齐。    - 会做排序(按时间升序)，同时返回的 Series 与 df 对齐（因此外层请在赋回 new_df 前做一次 df.sort_index()）。    """    # 1) 明确指定的 time_col    if time_col and time_col in df.columns:        ts = pd.to_datetime(df[time_col], errors="coerce")        # 若能解析，按时间排序，同时保留原行序映射        order = ts.sort_values().index        ts = ts.loc[order]        return ts    # 2) 索引可用    if isinstance(df.index, pd.DatetimeIndex):        ts = pd.Series(df.index, index=df.index)        # 索引已是时间，按索引排序        ts = ts.sort_index()        return ts    # 3) 自动从列名中识别    candidate_cols = [c for c in df.columns if _TIME_NAME_HINTS.search(str(c))]    for c in candidate_cols:        ts_try = pd.to_datetime(df[c], errors="coerce")        if ts_try.notna().sum() >= max(3, int(0.5 * len(df))):  # 至少能成功解析一半            order = ts_try.sort_values().index            return ts_try.loc[order]    # 4) 再试：对所有列尝试（兜底）    for c in df.columns:        try:            ts_try = pd.to_datetime(df[c], errors="coerce")            if ts_try.notna().sum() >= max(3, int(0.5 * len(df))):                order = ts_try.sort_values().index                return ts_try.loc[order]        except Exception:            pass    # 5) 全部失败：返回一个全 NaT 的占位（外层除法会得到 NaN）    return pd.Series(pd.NaT, index=df.index)def _align_df_to_ts(df: pd.DataFrame, ts: pd.Series) -> pd.DataFrame:    """    将 df 重排到与 ts 的索引顺序一致；如果 ts.index 非 df.index，则做对齐合并。    """    if ts.index.equals(df.index):        return df.loc[ts.index]    # 需要对齐：先构建一个临时 DataFrame，避免丢行    aligned = df.copy()    aligned["_tmp_key_order_restore_"] = np.arange(len(df))    # 以 ts.index 的顺序重排（ts 已按时间升序）    try:        aligned = aligned.reindex(ts.index)    except Exception:        # 若 ts.index 不是 df.index 的子集，做一个安全 join        tmp = pd.DataFrame({"__ts_order__": np.arange(len(ts))}, index=ts.index)        aligned = tmp.join(aligned, how="left")        aligned = aligned.sort_values("__ts_order__").drop(columns=["__ts_order__"])    return aligneddef _looks_cumulative(s: pd.Series, min_frac_nonneg: float = 0.85) -> bool:    """    粗判“累计量”：差分大多 >= 0（允许回零/抖动）。    """    try:        x = pd.to_numeric(s, errors="coerce")    except Exception:        return False    x = x.dropna()    if x.empty:        return False    d = x.diff()    # 忽略微小噪声    mad = x.mad() if hasattr(x, "mad") else np.nanmedian(np.abs(x - np.nanmedian(x)))    noise = mad * 1e-6 if (pd.notna(mad) and mad > 0) else 0.0    ok = (d >= -abs(noise)).sum()    tot = d.notna().sum()    if tot == 0:        return False    return ok / tot >= min_frac_nonnegdef _is_energy_like_column(name: str, unit_hint: Optional[str]) -> bool:    """    基于“名称/单位提示”的能量列快速筛。    """    if unit_hint:        uh = unit_hint.strip().lower()        if any(u in uh for u in ["kwh", "mwh", "wh", "mj", "gj"]):            return True    return bool(_CUMU_ENERGY_NAME_HINTS.search(str(name)))def _derive_power_from_energy(    ts: pd.Series,    energy: pd.Series,    cap_spike_quantile: float = 0.995,    max_spike_mult: float = 5.0) -> pd.Series:    """    功率(kW) = ΔE(kWh) / Δt(h)    - 逐行用真实时间间隔 dt 计算：支持不等间隔采样    - 负差分（回零/换表）置 NaN    - 上尾温和截断，去毛刺    """    x = pd.to_numeric(energy, errors="coerce")    # 计算 ΔE 与 Δt(h)    dE = x.diff()    dt_h = ts.diff().dt.total_seconds() / 3600.0    power = dE / dt_h    # 负差分（回零/换表） -> NaN    power = power.where(power >= 0)    # 去掉非有限值（dt=0 或解析失败）    power = power.replace([np.inf, -np.inf], np.nan)    # 温和截断（上尾毛刺）    try:        q = power.quantile(cap_spike_quantile)        if pd.notna(q) and q > 0:            power = power.clip(upper=q * max_spike_mult)    except Exception:        pass    return powerdef add_power_columns_from_cumulative_energy(    df: pd.DataFrame,    time_col: Optional[str] = None,    unit_map: Optional[dict] = None,             # <- 新增，来自上游的单位提示    register_role_callback=None,                 # <- 兼容调用，不使用也没关系    name_mutation: Optional[str] = None          # <- 兼容调用，不使用也没关系) -> pd.DataFrame:    """    从累计电量/能量列(Wh/kWh/MWh/MJ/GJ/含'電力量'等)推导瞬时功率(kW)，一次性 concat，避免碎片化。    仅对真正的“累计能量”列生效，显式排除温度/压力/流量/能力/COP/指令/異常/予備/TIME/INDEX等。    """    new_df = df.copy()    umap = unit_map or {}    # —— 准备干净的时间索引 ——    ts = _auto_pick_time_series(new_df, time_col)    tmp = new_df.copy()    tmp["_ts_"] = ts.values    tmp = tmp.dropna(subset=["_ts_"]).sort_values("_ts_")    tmp = tmp[~tmp["_ts_"].duplicated(keep="last")]    tmp = tmp.set_index(pd.to_datetime(tmp["_ts_"])).drop(columns=["_ts_"])    if not tmp.index.is_monotonic_increasing:        tmp = tmp.sort_index()    # —— 能量列筛选 ——    exclude_keys = ("温度","還気","往水","圧力","流量","能力","COP","指令","異常","予備","TIME","INDEX","コード")    def is_energy_col(col):        name = str(col)        unit_hint = (umap.get(col) or {}).get("unit") if isinstance(umap.get(col), dict) else umap.get(col)        name_ok = bool(_CUMU_ENERGY_NAME_HINTS.search(name)) and not any(k in name for k in exclude_keys)        unit_ok = isinstance(unit_hint, str) and unit_hint in {"Wh","kWh","MWh","MJ","GJ"}        return (name_ok or unit_ok) and not any(k in name for k in exclude_keys)    candidates = [c for c in tmp.columns if is_energy_col(c) and pd.api.types.is_numeric_dtype(tmp[c])]    if not candidates:        print("[INFO] 没有检测到累计能耗列用于推功率。")        return new_df    dt_hours = tmp.index.to_series().diff().dt.total_seconds().div(3600).to_numpy()    new_cols = {}    for col in candidates:        s = pd.to_numeric(tmp[col], errors="coerce")        dE = s.diff()        dE[dE < 0] = pd.NA  # 表计回零/换表        # —— 单位归一到 kWh ——        u = (umap.get(col) or {}).get("unit") if isinstance(umap.get(col), dict) else umap.get(col)        u = (u or "").strip()        if u == "Wh":            dE_kWh = dE / 1000.0        elif u == "MWh":            dE_kWh = dE * 1000.0        elif u == "MJ":            dE_kWh = dE * 0.2777777778        elif u == "GJ":            dE_kWh = dE * 277.7777778        else:            dE_kWh = dE  # 默认为 kWh        P_kW = pd.Series(dE_kWh.to_numpy() / dt_hours, index=tmp.index).replace([np.inf, -np.inf], pd.NA)        base = str(col).replace("電力量", "").replace("積算", "").replace("energy", "").strip()        if base.endswith("()"):            base = base[:-2].rstrip()        final_name = f"{base} 電力(kW)" if base else f"{col} 電力(kW)"        # 去掉重复后缀，比如 "... 電力(kW) 電力(kW)"        final_name = re.sub(r'( 電力\(kW\))\s*( 電力\(kW\))+', r'\1', final_name)        new_cols[final_name] = P_kW    new_block = pd.DataFrame(new_cols, index=tmp.index)    if not new_block.index.equals(new_df.index):        new_block = new_block.reindex(new_df.index)    new_df = pd.concat([new_df, new_block], axis=1).copy()    print("[POST] Derived power columns:", list(new_cols.keys()))    return new_dfdef ensure_power_columns(df, time_col):    """    从累计能量列推导区间平均功率(kW)；保持向后兼容：    - 保留原有 '電力量' / 'energy' 条件    - 额外支持 WH/kWh/MWh/積算/累计/累積    - 排除温度/压力/INV/%/状态/告警等误判    - 支持不等间隔时间（优先逐点Δt，回退中位Δt）    """    # 1) 备份：中位Δt（小时）    dt_hours = None    if time_col in df.columns:        t = pd.to_datetime(df[time_col], errors='coerce').sort_values()        if t.notna().sum() >= 2:            dt_hours = (t.diff().dt.total_seconds().median() or 0) / 3600.0    # 2) 识别规则    ENERGY_TOKEN = re.compile(r'\b(kwh|wh|mwh)\b', re.IGNORECASE)    EXCLUDE_TOKENS = ('温度','還温','往温','圧力','pressure','temp',                      '指令','command','status','alarm',                      'inv','%','mv','開度','set','sp','設定','code')    for col in df.columns:        name = str(col)        low  = name.lower()        # 原有可识别条件（保留）        base_match = ('電力量' in name) or ('energy' in low) or ('積算' in name) or ('累计' in name) or ('累積' in name)        # 新增可识别条件        extra_match = bool(ENERGY_TOKEN.search(low))        # 排除明显不是能量的列        excluded = any(tok in low for tok in [t.lower() for t in EXCLUDE_TOKENS])        if not ((base_match or extra_match) and not excluded):            continue        series = pd.to_numeric(df[col], errors='coerce')        diff = series.diff()        # 逐点Δt（优先）        if time_col in df.columns:            dt = pd.to_datetime(df[time_col], errors='coerce').diff().dt.total_seconds() / 3600.0            kw = diff / dt        else:            if not dt_hours or dt_hours == 0:                continue            kw = diff / dt_hours        # 负差分（回零/换表）置0；去无穷        kw = kw.replace([float('inf'), float('-inf')], pd.NA).clip(lower=0)        # 统一新列名：尽量把“電力量/積算”等换成“電力(kW)”，否则追加后缀        new_col = (name.replace('電力量', '電力')                        .replace('積算', '')                        .strip())        if '電力' not in new_col:            new_col = f"{new_col} 電力(kW)"        df[new_col] = kw    return dfdef derive_power_from_energy(df, time_col, energy_col, new_col_name=None):    """    根据累计能耗列（Wh/kWh）推算区间功率(kW)。    - 自动识别单位：列名或单位中含 kwh -> kWh；wh -> Wh    - 用时间差(小时)做差分    - 避免重复创建同名列    返回：新功率列名 或 None    """    import numpy as np    if energy_col not in df.columns:        return None    s = pd.to_numeric(df[energy_col], errors="coerce")    if s.notna().sum() < 2:        return None    # 单位倍率：kWh -> 1， Wh -> 1/1000（转成 kWh）    name = energy_col.lower()    if "kwh" in name:        factor = 1.0    elif re.search(r"\bwh\b", name) or ("wh" in name):        factor = 1/1000.0    else:        # 不确定时直接按 kWh 处理        factor = 1.0    # 时间差(小时)    t = pd.to_datetime(df[time_col], errors='coerce')    dt_h = (t - t.shift(1)).dt.total_seconds() / 3600.0    # 差分(kWh) / 小时 = kW    power = (s - s.shift(1)) * factor / dt_h    power = power.replace([np.inf, -np.inf], np.nan)    # 列名    if not new_col_name:        base = f"{energy_col} 電力(kW)"    else:        base = f"{new_col_name}"    colname = base    i = 2    while colname in df.columns:        colname = f"{base} {i}"        i += 1    df[colname] = power    print(f"[POST] Derived power column from energy: {colname}")    return colnamedef add_power_columns_from_energy_generic(    df: pd.DataFrame,    time_col: Optional[str] = None,    unit_map: Optional[dict] = None,) -> pd.DataFrame:    """    兼容两种来源：    1) 累计表计(单调递增，偶有回零/换表) -> 差分/Δt    2) 分段能量(如 “...日算値”、“期间kWh”) -> 直接 E_segment / Δt    只做“新增列”，不改动原列和既有逻辑。    """    new_df = df.copy()    umap = unit_map or {}    ts = _auto_pick_time_series(new_df, time_col)    tmp = (new_df.assign(_ts_=ts).dropna(subset=["_ts_"])                     .sort_values("_ts_").drop_duplicates("_ts_", keep="last"))    tmp.index = pd.to_datetime(tmp["_ts_"]); tmp = tmp.drop(columns=["_ts_"])    if not tmp.index.is_monotonic_increasing:        tmp = tmp.sort_index()    dt_hours = tmp.index.to_series().diff().dt.total_seconds().div(3600).to_numpy()    def _unit_of(col):        u = umap.get(col) if isinstance(umap.get(col), (str, dict)) else umap.get(str(col))        if isinstance(u, dict): u = u.get("unit")        return (u or "").strip()    def _to_kWh(dE, u):        if u == "Wh":   return dE / 1000.0        if u == "MWh":  return dE * 1000.0        if u == "MJ":   return dE * 0.2777777778        if u == "GJ":   return dE * 277.7777778        return dE  # 默认为 kWh    def _is_cumulative_series(s: pd.Series) -> bool:        """判定是否“累计表计”：大多数差分>=0，允许少量小幅回零/换表"""        x = pd.to_numeric(s, errors="coerce")        d = x.diff()        if d.notna().sum() < 3:            return False        neg_ratio = (d < -1e-6).sum() / d.notna().sum()        # 单调递增为主，偶发回零        return neg_ratio < 0.1 and x.notna().sum() >= 5    new_cols = {}    for col in tmp.columns:        name = str(col)        u = _unit_of(col)        if u not in {"Wh","kWh","MWh","MJ","GJ"} and not re.search(r"(電力量|積算|kWh|Wh|MJ|GJ)", name, flags=re.I):            continue  # 既无单位提示也无名称暗示，就跳过        s = pd.to_numeric(tmp[col], errors="coerce")        if s.notna().sum() < 3:            continue        if _is_cumulative_series(s):            dE = s.diff()            dE[dE < 0] = pd.NA            dE_kWh = _to_kWh(dE, u or ("kWh" if "kWh" in name else ""))            P = pd.Series(dE_kWh.to_numpy() / dt_hours, index=tmp.index)            suffix = " 電力(kW)"        else:            # 分段能量：直接 E_segment / Δt            Eseg_kWh = _to_kWh(s, u or ("kWh" if "kWh" in name else ""))            P = pd.Series(Eseg_kWh.to_numpy() / dt_hours, index=tmp.index)            suffix = " 平均電力(kW)"  # 与累计表计区分命名        P = P.replace([np.inf, -np.inf], pd.NA)        # 保留原列名，直接追加后缀，避免出现“（）”        base = name.strip()        final = f"{base}{suffix}"        # 去重连续后缀        final = re.sub(r"( (平均)?電力\(kW\))\s*( (平均)?電力\(kW\))+", r"\1", final)        # 清理可能出现的全角/半角空括号        final = re.sub(r"[（(]\s*[)）]", "", final)        new_cols[final] = P    if new_cols:        block = pd.DataFrame(new_cols, index=tmp.index).reindex(new_df.index)        new_df = pd.concat([new_df, block], axis=1)    return new_dfdef classify_role_fallback_jp(col: str, unit: str) -> str:    name = str(col)    u = (unit or "").strip()    # 只在“原规则没判出来”时用这些：    if re.search(r"(往水温度|供水温|送水温|出水温|出口温度)", name): return "heat_source_supply_temp"    if re.search(r"(還水温度|回水温|入口温度)", name): return "heat_source_return_temp"    if re.search(r"(^|[^ポンプ])流量(?!指令)", name) or u in {"L/s","L/min","m³/h"}: return "heat_source_flow"    if re.search(r"消費電力（瞬時値）|消費電力\(瞬時値\)", name) or (u=="kW" and "能力" not in name): return "heat_source_power"    if re.search(r"(運転容量|冷却能力/加熱能力（瞬時値）)", name) or ("能力" in name and u=="kW"): return "heat_source_capacity"    if re.search(r"(電力量|積算|日算値)", name) or u in {"Wh","kWh","MWh","MJ","GJ"}: return "power_accum"    if "COP" in name: return "cop"    return ""